window.BYWAYS_DATA=[{"id":"a1a-scenic-and-historic-coastal-byway","name":"A1A Scenic and Historic Coastal Byway","tier":"all-american","region":"South","regionLabel":"Florida","states":"Florida","sub":"Florida","length":"339 mi","lengthMi":339,"lat":28.6,"lng":-81.5,"approxLoc":true,"qualities":[],"blurb":"State Road A1A (SR A1A) is a major north–south Florida State Road consisting of seven separate sections running a total of 338.752 miles (545.168 km) along the Atlantic Ocean, from Key West at the southern tip of Florida, to Fernandina Beach, just south of Georgia on Amelia Island, before turning inland to Callahan. It is the main road through most oceanfront towns. Part of SR A1A between Flagler Beach and Jacksonville Beach is designated the A1A Scenic and Historic Coastal Byway, a National Scenic Byway. SR A1A is","link":"https://en.wikipedia.org/wiki/Florida_State_Road_A1A","wiki":["A1A Scenic and Historic Coastal Byway","Florida State Road A1A"],"endpoints":{"from":"Key West, FL","to":"Callahan, FL","via":["Palm Beach, FL","New Smyrna Beach, FL","Jacksonville, FL"]}},{"id":"acadia-all-american-road","name":"Acadia All-American Road","tier":"all-american","region":"East","regionLabel":"Mount Desert Island","states":"Maine","sub":"Maine","length":"40 mi","lengthMi":40,"lat":44.3503,"lng":-68.2039,"approxLoc":false,"qualities":[],"blurb":"The Acadia All-American Road runs about 40 miles from Trenton onto Mount Desert Island, through Bar Harbor and around Acadia National Park’s 27-mile Park Loop Road — past Sand Beach, Thunder Hole, Jordan Pond and the auto road to the summit of Cadillac Mountain. Designated an All-American Road for the coast-and-mountain scenery packed into one compact island loop.","link":"https://www.exploremaine.org/byways/downeast/acadia.shtml","wiki":["Acadia National Park","Park Loop Road","Acadia All-American Road"],"time":"3 hr","mapCap":"Mount Desert Island, Maine · Acadia byway loop","endpoints":{"from":"Trenton, ME","to":"Northeast Harbor, ME","via":["Bar Harbor, ME"]}},{"id":"alaska-marine-highway","name":"Alaska Marine Highway","tier":"all-american","region":"Alaska","regionLabel":"Alaska","states":"Alaska","sub":"Alaska","length":"","lengthMi":null,"lat":58.3598,"lng":-134.5268,"approxLoc":false,"qualities":[],"blurb":"The Alaska Marine Highway (AMH) or the Alaska Marine Highway System (AMHS) is a ferry service operated by the U.S. state of Alaska. It has its headquarters in Ketchikan, Alaska. AMHS is part of Alaska Department of Transportation and Public Facilities. The Alaska Marine Highway System operates along the south-central coast of the state, the eastern Aleutian Islands and the Inside Passage of Alaska and British Columbia, Canada. Ferries serve communities in Southeast Alaska that have no road access, and the vessels c","link":"https://en.wikipedia.org/wiki/Alaska_Marine_Highway","wiki":["Alaska Marine Highway","Alaska Marine Highway"]},{"id":"battle-road-scenic-byway","name":"Battle Road Scenic Byway","tier":"all-american","region":"East","regionLabel":"New England","states":"Massachusetts","sub":"Massachusetts","length":"","lengthMi":null,"lat":42.3,"lng":-71.8,"approxLoc":true,"qualities":[],"blurb":"Battle Road, formerly known as the Old Concord Road and the Bay Road, is a historic road in Massachusetts, United States. It was formerly part of the main road connecting Lexington, Lincoln and Concord, three of the main towns involved in the American Revolutionary War. It was on Battle Road that thousands of colonial militia and British regulars fought during the redcoats' retreat from Concord to Boston on the morning and afternoon of April 19, 1775.","link":"https://en.wikipedia.org/wiki/Battle_Road","wiki":["Battle Road Scenic Byway","Battle Road"]},{"id":"beartooth-highway","name":"Beartooth Highway","tier":"all-american","region":"Rockies","regionLabel":"Northern Rockies","states":"Montana · Wyoming","sub":"Montana · Wyoming","length":"","lengthMi":null,"lat":45.1576,"lng":-109.2688,"approxLoc":false,"qualities":[],"blurb":"The Beartooth Highway is an All-American Road in the western United States on a section of U.S. Route 212 in Montana and Wyoming between Red Lodge and the Northeast entrance of Yellowstone National Park. It crests at Beartooth Pass in Wyoming at 10,947 feet (3,337 m) above sea level, and was called \"the most beautiful drive in America,\" by late CBS News correspondent Charles Kuralt. Because of heavy snowfall at the top, the pass is usually open for about five months per year, from mid-May to mid-October, weather co","link":"https://www.fhwa.dot.gov/byways","wiki":["Beartooth Highway"],"endpoints":{"from":"Red Lodge, MT","to":"Cooke City, MT"}},{"id":"big-sur-coast-highway","name":"Big Sur Coast Highway","tier":"all-american","region":"West","regionLabel":"California","states":"California","sub":"California","length":"71 mi","lengthMi":71,"lat":36.2704,"lng":-121.8081,"approxLoc":false,"qualities":[],"blurb":"Big Sur Coast Highway is a section of California State Route 1 through the Big Sur region of California that is widely considered to be one of the most scenic driving routes in the United States, if not the world. It is both a National Scenic Byway and a California Scenic Highway, and was described by Australian painter Francis McComas as the \"greatest meeting of land and water in the world\". The winding, narrow road, often cut into the face of towering seaside cliffs, is a \"symbolic image\" of Big Sur. Condé Nast T","link":"https://www.fhwa.dot.gov/byways","wiki":["Big Sur Coast Highway"],"endpoints":{"from":"Carmel-by-the-Sea, CA","to":"San Simeon, CA","via":["Big Sur, CA"]}},{"id":"blue-ridge-parkway","name":"Blue Ridge Parkway","tier":"all-american","region":"East","regionLabel":"Appalachians","states":"Virginia · North Carolina","sub":"Shenandoah → Great Smokies","length":"469 mi","lengthMi":469,"lat":36.01,"lng":-81.62,"approxLoc":false,"qualities":["Scenic","Natural","Historic","Cultural","Recreational"],"blurb":"“America's Favorite Drive” runs 469 miles along the crest of the Blue Ridge, connecting Shenandoah National Park to Great Smoky Mountains National Park. Free of commercial traffic and stoplights, the Parkway rolls past split-rail fences, restored mountain farms, and mile after mile of layered blue ridgelines, with overlooks numbered by milepost the whole way.","link":"https://www.nps.gov/blri/planyourvisit/index.htm","wiki":["Linn Cove Viaduct","Mount Mitchell","Grandfather Mountain"],"time":"Multi-day","parkCode":"blri","season":"Year-round (spring–fall best)","mapCap":"Shenandoah → Blue Ridge crest → Great Smokies","planNote":"Sections close in winter ice and for landslide repairs — check the real-time road map before you go. Fall color peaks from north to south through October; the Linn Cove Viaduct and the highlands around Mount Mitchell are the most photographed stretches.","film":[{"q":["Blue Ridge Parkway"],"cap":"Layered ridgelines from the crest"},{"q":["Linn Cove Viaduct"],"cap":"The Linn Cove Viaduct"},{"q":["Mount Mitchell"],"cap":"Mount Mitchell — highest peak in the East"},{"q":["Mabry Mill"],"cap":"Mabry Mill, milepost 176"}],"highlights":[{"n":"Linn Cove Viaduct","q":["Linn Cove Viaduct"],"d":"The engineering marvel around Grandfather Mountain","lat":36.096,"lng":-81.809},{"n":"Mabry Mill","q":["Mabry Mill"],"d":"The most photographed spot on the Parkway","lat":36.752,"lng":-80.406},{"n":"Mount Mitchell","q":["Mount Mitchell"],"d":"Highest summit east of the Mississippi","lat":35.765,"lng":-82.265},{"n":"Craggy Gardens","q":["Craggy Gardens"],"d":"Rhododendron balds above Asheville","lat":35.699,"lng":-82.38}],"endpoints":{"from":"Afton, VA","to":"Cherokee, NC","via":["Roanoke, VA","Blowing Rock, NC","Asheville, NC"]}},{"id":"chesapeake-country-scenic-byway","name":"Chesapeake Country Scenic Byway","tier":"all-american","region":"East","regionLabel":"Mid-Atlantic","states":"Maryland","sub":"Maryland","length":"","lengthMi":null,"lat":39,"lng":-76.8,"approxLoc":true,"qualities":[],"blurb":"The Maryland Scenic Byways system consists of nineteen byways that pass through scenic and historic areas across the U.S. state of Maryland, with four of them designated as National Scenic Byways and two of them designated as All-American Roads. The byways pass through a variety of surroundings, such as the mountains of Western Maryland, the rolling countryside in the northern part of the state, urban sites in the Baltimore and Washington, D.C., areas, small towns and wildlife areas along the Chesapeake Bay, and be","link":"https://en.wikipedia.org/wiki/List_of_Maryland_Scenic_Byways","wiki":["Chesapeake Country Scenic Byway","List of Maryland Scenic Byways"]},{"id":"chinook-scenic-byway","name":"Chinook Scenic Byway","tier":"all-american","region":"West","regionLabel":"Cascades","states":"Washington","sub":"Washington","length":"107 mi","lengthMi":107,"lat":46.2729,"lng":-123.9454,"approxLoc":false,"qualities":[],"blurb":"State Route 410 (SR 410, partially named the Chinook Scenic Byway, and also named the Stephen Mather Memorial Parkway) is a 107.44-mile (172.91 km) long state highway that traverses Pierce, King, and Yakima counties in the US state of Washington. It begins at an interchange with SR 167 in Sumner and travels southeast across the Cascade Range to a junction with U.S. Route 12 (US 12) in Naches. While the western part of SR 410 is a freeway that serves built-up, urban areas, the remainder of the route is a surface roa","link":"https://www.fhwa.dot.gov/byways","wiki":["Chinook Scenic Byway","Washington State Route 410"],"endpoints":{"from":"Sumner, WA","to":"Naches, WA","via":["White River, WA","Greenwater River, WA","Cayuse Pass, WA"]}},{"id":"colonial-parkway","name":"Colonial Parkway","tier":"all-american","region":"East","regionLabel":"Blue Ridge","states":"Virginia","sub":"Virginia","length":"23 mi","lengthMi":23,"lat":37.2762,"lng":-76.6156,"approxLoc":false,"qualities":[],"blurb":"Colonial Parkway is a 23-mile (37 km) scenic parkway linking the three points of Virginia's Historic Triangle, Jamestown, Williamsburg, and Yorktown. It is part of the National Park Service's Colonial National Historical Park. Virginia's official state classification for the parkway is State Route 90003. With portions built between 1930 and 1957, it links the three communities via a roadway shielded from views of commercial development. The roadway is toll-free, is free of semi trucks, and has speed limits of aroun","link":"https://en.wikipedia.org/wiki/Colonial_Parkway","wiki":["Colonial Parkway","Colonial Parkway"],"endpoints":{"from":"Yorktown, VA","to":"Jamestown, VA","via":["City of Williamsburg, VA"]}},{"id":"creole-nature-trail","name":"Creole Nature Trail","tier":"all-american","region":"South","regionLabel":"Gulf Coast","states":"Louisiana","sub":"Louisiana","length":"","lengthMi":null,"lat":31,"lng":-92,"approxLoc":true,"qualities":[],"blurb":"The Louisiana Scenic Byways are a network of roadways within the U.S. state of Louisiana that have been deemed of cultural, historical, or scenic value. The routes follow various segments of the state-maintained highway system, usually rural in character, and are mostly located in the central and southern areas of the state.","link":"https://en.wikipedia.org/wiki/List_of_Louisiana_Scenic_Byways","wiki":["Creole Nature Trail","List of Louisiana Scenic Byways"]},{"id":"flaming-gorge-green-river-basin-scenic-byway","name":"Flaming Gorge-Green River Basin Scenic Byway","tier":"all-american","region":"Rockies","regionLabel":"Northern Rockies","states":"Wyoming","sub":"Wyoming","length":"","lengthMi":null,"lat":43,"lng":-107.5,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Flaming Gorge-Green River Basin Scenic Byway"]},{"id":"florida-keys-scenic-highway","name":"Florida Keys Scenic Highway","tier":"all-american","region":"South","regionLabel":"Florida","states":"Florida","sub":"Florida","length":"113 mi","lengthMi":113,"lat":28.6,"lng":-81.5,"approxLoc":true,"qualities":[],"blurb":"The Overseas Highway is a 113-mile (181.9 km) highway carrying U.S. Route 1 (US 1) through the Florida Keys to Key West. Large parts of it were built on the former right-of-way of the Overseas Railroad, the Key West Extension of the Florida East Coast Railway. Completed in 1912, the Overseas Railroad was heavily damaged and partially destroyed in the 1935 Labor Day hurricane. The Florida East Coast Railway was financially unable to rebuild the destroyed sections, so the roadbed and remaining bridges were sold to th","link":"https://en.wikipedia.org/wiki/Overseas_Highway","wiki":["Florida Keys Scenic Highway","Overseas Highway"],"endpoints":{"from":"Key West, FL","to":"Key Largo, FL","via":["Ramrod Key, FL","Marathon (Long Point Key), FL","Islamorada, FL"]}},{"id":"george-washington-memorial-parkway","name":"George Washington Memorial Parkway","tier":"all-american","region":"East","regionLabel":"Blue Ridge","states":"Virginia","sub":"Virginia","length":"25 mi","lengthMi":25,"lat":38.9637,"lng":-77.1775,"approxLoc":false,"qualities":[],"blurb":"The George Washington Memorial Parkway, colloquially the G.W. Parkway, is a 25-mile-long (40 km) limited-access parkway that runs along the south bank of the Potomac River from Mount Vernon, northwest to McLean, Virginia, United States, and is maintained by the National Park Service (NPS). It is located almost entirely in Northern Virginia, except for a short portion of the parkway northwest of the Arlington Memorial Bridge that passes over Columbia Island in Washington, D.C. The parkway is separated into two secti","link":"https://en.wikipedia.org/wiki/George_Washington_Memorial_Parkway","wiki":["George Washington Memorial Parkway","George Washington Memorial Parkway"],"endpoints":{"from":"Mount Vernon, VA","to":"McLean, VA","via":["City of Alexandria, VA","Long Bridge Park, VA","North Highland, VA"]}},{"id":"great-river-road","name":"Great River Road","tier":"all-american","region":"South","regionLabel":"Ozarks","states":"Arkansas · Illinois · Iowa · Kentucky · Louisiana · Minnesota · Mississippi · Missouri · Tennessee · Wisconsin","sub":"Arkansas · Illinois","length":"2340 mi","lengthMi":2340,"lat":33.8143,"lng":-91.1579,"approxLoc":false,"qualities":[],"blurb":"The Great River Road is a collection of state and local roads that follow the course of the Mississippi River. It begins at Lake Itasca, Minnesota, and passes through Wisconsin, Iowa, Illinois, Missouri, Kentucky, Tennessee, Arkansas, and Mississippi, before terminating in Venice, Louisiana. It formerly extended north into Canada, serving the provinces of Ontario and Manitoba. The road is designated as both a National Scenic Byway and an All-American Road in several states along the route. The term \"Great River Roa","link":"https://www.fhwa.dot.gov/byways","wiki":["Great River Road"]},{"id":"harriet-tubman-underground-railroad-byway","name":"Harriet Tubman Underground Railroad Byway","tier":"all-american","region":"East","regionLabel":"Mid-Atlantic","states":"Maryland","sub":"Maryland","length":"","lengthMi":null,"lat":39,"lng":-76.8,"approxLoc":true,"qualities":[],"blurb":"Harriet Tubman Underground Railroad Scenic Byway may refer to: Harriet Tubman Underground Railroad Byway (Delaware), part of the Delaware Byways system Harriet Tubman Underground Railroad Scenic Byway (Maryland), part of the Maryland Scenic Byways system","link":"https://en.wikipedia.org/wiki/Harriet_Tubman_Underground_Railroad_Scenic_Byway","wiki":["Harriet Tubman Underground Railroad Byway","Harriet Tubman Underground Railroad Scenic Byway"]},{"id":"hells-canyon-scenic-byway","name":"Hells Canyon Scenic Byway","tier":"all-american","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"218 mi","lengthMi":218,"lat":44.4077,"lng":-123.3836,"approxLoc":false,"qualities":[],"blurb":"Hells Canyon Scenic Byway is a designated All-American Road in the U.S. state of Oregon. It is located at the northeast corner of Oregon and comprises Oregon Route 82, Oregon Route 350, Forest Roads 39 and 3365, and most of Oregon Route 86. From the west, the byway begins at the intersection of Oregon Route 82 and Interstate 84 near La Grande and ends near Baker City, at the junction of Interstate 84 and Oregon Route 86. It is 218.4 miles (351.5 km) long.","link":"https://www.fhwa.dot.gov/byways","wiki":["Hells Canyon Scenic Byway"]},{"id":"historic-columbia-river-highway","name":"Historic Columbia River Highway","tier":"all-american","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"75 mi","lengthMi":75,"lat":45.5407,"lng":-122.3873,"approxLoc":false,"qualities":[],"blurb":"The Historic Columbia River Highway is an approximately 75-mile-long (121 km) scenic highway in the U.S. state of Oregon between Troutdale and The Dalles, built through the Columbia River Gorge between 1913 and 1922. As the first planned scenic roadway in the United States, it has been recognized in numerous ways, including being listed on the National Register of Historic Places, being designated as a National Historic Landmark by the U.S. Secretary of the Interior, being designated as a National Historic Civil En","link":"https://www.fhwa.dot.gov/byways","wiki":["Historic Columbia River Highway"],"endpoints":{"from":"Troutdale, OR","to":"The Dalles, OR","via":["Cascade Locks, OR"]}},{"id":"historic-national-road","name":"Historic National Road","tier":"all-american","region":"Midwest","regionLabel":"Midwest","states":"Illinois · Indiana · Maryland · Ohio · Pennsylvania · West Virginia","sub":"Illinois · Indiana","length":"131 mi","lengthMi":131,"lat":40,"lng":-89.2,"approxLoc":true,"qualities":[],"blurb":"The National Road—formerly the Cumberland Road and later celebrated as \"Main Street of America\"—was the United States' first great federally financed highway and a proving ground for national‑scale internal improvements. Originating at the head of navigation on the Potomac River in Cumberland, Maryland, the 4-rod (66 ft; 20 m) wide engineered turnpike was authorized on March 29, 1806, when President Thomas Jefferson signed \"An Act to regulate the laying out and making a road from Cumberland … to the State of Ohio\".","link":"https://en.wikipedia.org/wiki/National_Road","wiki":["Historic National Road","National Road"]},{"id":"historic-route-66","name":"Historic Route 66","tier":"all-american","region":"Southwest","regionLabel":"Desert Southwest","states":"Arizona · Illinois · Missouri · New Mexico · Oklahoma","sub":"Arizona · Illinois","length":"2448 mi","lengthMi":2448,"lat":35.26,"lng":-111.9527,"approxLoc":false,"qualities":[],"blurb":"U.S. Route 66 or U.S. Highway 66 (US 66 or Route 66) was one of the original highways in the United States Numbered Highway System. Established on November 11, 1926, with signage erected the following year, the highway ran from Chicago, Illinois, through Missouri, Kansas, Oklahoma, Texas, New Mexico, and Arizona before terminating in Santa Monica, California, covering 2,448 miles (3,940 km). US 66 became a major route for westward migration, particularly during the Dust Bowl of the 1930s, and contributed to the eco","link":"https://www.fhwa.dot.gov/byways","wiki":["Historic Route 66","U.S. Route 66"]},{"id":"international-selkirk-loop","name":"International Selkirk Loop","tier":"all-american","region":"Rockies","regionLabel":"Northern Rockies","states":"Idaho · Washington","sub":"Idaho · Washington","length":"280 mi","lengthMi":280,"lat":44.4,"lng":-114.6,"approxLoc":true,"qualities":[],"blurb":"The International Selkirk Loop is a 280-mile-long (450 km) scenic highway in the U.S. states of Idaho and Washington, as well as the Canadian province of British Columbia. The loop encircles the Selkirk Mountain Range, and offers several side trips aside from the main route. Included on the loop is the Kootenay Lake Ferry, the longest free ferry in the world. The portion of the loop in the United States has been designated an All-American Road by the United States Department of Transportation.","link":"https://en.wikipedia.org/wiki/International_Selkirk_Loop","wiki":["International Selkirk Loop","International Selkirk Loop"],"endpoints":{"from":"Newport, ID","to":"Priest River, ID","via":["Nelway, ID","Kootenay Lake, ID","Porthill, ID"]}},{"id":"lakes-to-locks-passage","name":"Lakes to Locks Passage","tier":"all-american","region":"East","regionLabel":"Upstate New York","states":"New York","sub":"New York","length":"","lengthMi":null,"lat":42.9,"lng":-75.5,"approxLoc":true,"qualities":[],"blurb":"The Lakes to Locks Passage in the United States and the corresponding Route du Richelieu in Canada form a scenic byway network located in northeastern New York and southern Quebec. This byway connects a series of water routes including the upper Hudson River, Champlain Canal, Lake George, and Lake Champlain. This network is part of a historically significant transportation route linking upstate New York with the Canadian province of Quebec. In the United States, the Lakes to Locks Passage is designated as a New Yor","link":"https://en.wikipedia.org/wiki/Lakes_to_Locks_Passage","wiki":["Lakes to Locks Passage","Lakes to Locks Passage"]},{"id":"las-vegas-strip","name":"Las Vegas Strip","tier":"all-american","region":"West","regionLabel":"Great Basin","states":"Nevada","sub":"Nevada","length":"4 mi","lengthMi":4,"lat":36.1194,"lng":-115.1743,"approxLoc":false,"qualities":[],"blurb":"The Las Vegas Strip is a stretch of Las Vegas Boulevard in Clark County, Nevada, that is known for its concentration of resort hotels and casinos. The Strip, as it is known, is about 4.2 mi (6.8 km) long, and is immediately south of the Las Vegas city limits in the unincorporated towns of Paradise and Winchester, but is often referred to simply as \"Las Vegas\". Many of the largest hotel casino and resort properties in the world are on the Strip. Its hotels, casinos, restaurants, residential high-rises, entertainment","link":"https://www.fhwa.dot.gov/byways","wiki":["Las Vegas Strip"]},{"id":"natchez-trace-parkway","name":"Natchez Trace Parkway","tier":"all-american","region":"South","regionLabel":"Deep South","states":"Alabama · Mississippi · Tennessee","sub":"Alabama · Mississippi","length":"444 mi","lengthMi":444,"lat":34.8524,"lng":-87.9228,"approxLoc":false,"qualities":[],"blurb":"The Natchez Trace Parkway is a limited-access national parkway in the Southeastern United States that commemorates the historic Natchez Trace and preserves sections of that original trail. Its central feature is a two-lane road that extends 444 miles (715 km) from Natchez, Mississippi, to Nashville, Tennessee. Access to the parkway is limited, with more than 50 access points in Mississippi, Alabama, and Tennessee. The southern end of the route is in Natchez at its intersection with Liberty Road, and the northern en","link":"https://en.wikipedia.org/wiki/Natchez_Trace_Parkway","wiki":["Natchez Trace Parkway","Natchez Trace Parkway"],"endpoints":{"from":"Natchez, MS","to":"Nashville, TN","via":["Jackson, MS","Tupelo, MS"]}},{"id":"newfound-gap-road","name":"Newfound Gap Road","tier":"all-american","region":"East","regionLabel":"Appalachians","states":"North Carolina · Tennessee","sub":"North Carolina · Tennessee","length":"","lengthMi":null,"lat":35.509,"lng":-83.3062,"approxLoc":false,"qualities":[],"blurb":"Newfound Gap (el. 5,048 feet (1,539 m)) is a mountain pass located near the center of the Great Smoky Mountains National Park of the southern Appalachian Mountains in the United States. Situated along the border of Tennessee and North Carolina, the state line crosses the gap, as does Newfound Gap Road (which overlaps U.S. Route 441 through the park and ends at the park's boundaries near Gatlinburg, Tennessee, and Cherokee, North Carolina). The Appalachian Trail also traverses the gap, as do a few other hiking trail","link":"https://www.fhwa.dot.gov/byways","wiki":["Newfound Gap Road","Newfound Gap"]},{"id":"north-shore-scenic-drive","name":"North Shore Scenic Drive","tier":"all-american","region":"Midwest","regionLabel":"North Woods","states":"Minnesota","sub":"Minnesota","length":"150 mi","lengthMi":150,"lat":46.3,"lng":-94.3,"approxLoc":true,"qualities":[],"blurb":"Minnesota State Highway 61 (MN 61) is a 150.321-mile-long (241.918 km) highway in northeast Minnesota, which runs from a junction with Interstate 35 (I-35) in Duluth at 26th Avenue East, and continues northeast to its northern terminus at the Canadian border near Grand Portage, connecting to Ontario Highway 61 at the Pigeon River Bridge. The route is a scenic highway, following the North Shore of Lake Superior, and is part of the Lake Superior Circle Tour designation that runs through Minnesota, Ontario, Michigan, ","link":"https://en.wikipedia.org/wiki/Minnesota_State_Highway_61","wiki":["North Shore Scenic Drive","Minnesota State Highway 61"],"endpoints":{"from":"Duluth, MN","to":"Pigeon River, MN","via":["Silver Bay, MN","Little Marais, MN","Lutsen, MN"]}},{"id":"northwest-passage-scenic-byway","name":"Northwest Passage Scenic Byway","tier":"all-american","region":"Rockies","regionLabel":"Northern Rockies","states":"Idaho","sub":"Idaho","length":"174 mi","lengthMi":174,"lat":44.4,"lng":-114.6,"approxLoc":true,"qualities":[],"blurb":"U.S. Route 12 (US-12) is a United States Numbered Highway in North Central Idaho. It extends 174.410 miles (280.686 km) from the Washington state line in Lewiston east to the Montana state line at Lolo Pass, generally along the route of the Lewis and Clark Expedition, and is known as the Northwest Passage Scenic Byway. It was previously known as the Lewis and Clark Highway.","link":"https://en.wikipedia.org/wiki/U.S._Route_12_in_Idaho","wiki":["Northwest Passage Scenic Byway","U.S. Route 12 in Idaho"],"endpoints":{"from":"Snake River, ID","to":"Lolo Pass, ID","via":["Lewiston, ID","Greer, ID","Kamiah, ID"]}},{"id":"pacific-coast-scenic-byway","name":"Pacific Coast Scenic Byway","tier":"all-american","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"1500 mi","lengthMi":1500,"lat":45.4524,"lng":-123.8432,"approxLoc":false,"qualities":[],"blurb":"U.S. Route 101, or U.S. Highway 101 (US 101), is a major north–south highway that traverses the states of California, Oregon, and Washington on the West Coast of the United States. It is part of the United States Numbered Highway System and runs for over 1,500 miles (2,400 km) along the Pacific Ocean. The highway is also known by various names, including El Camino Real in parts of California, the Oregon Coast Highway, and the Olympic Highway in Washington. Despite its three-digit number, normally used for spur rout","link":"https://www.fhwa.dot.gov/byways","wiki":["Pacific Coast Scenic Byway","U.S. Route 101"],"endpoints":{"from":"Astoria, OR","to":"Brookings, OR","via":["Newport, OR","Coos Bay, OR"]}},{"id":"red-rock-scenic-byway","name":"Red Rock Scenic Byway","tier":"all-american","region":"Southwest","regionLabel":"Desert Southwest","states":"Arizona","sub":"Arizona","length":"8 mi","lengthMi":8,"lat":34.8628,"lng":-111.7633,"approxLoc":false,"qualities":[],"blurb":"State Route 179, also known as SR 179 or the Red Rock Scenic Byway, is a north–south state highway in Arizona, United States, running from Interstate 17 to SR 89A in Sedona, entering Coconino County from Yavapai County. In 2006, the United States Department of Transportation awarded SR 179 its highest designation within the National Scenic Byways Program: the All-American Road designation, due to the red rock and sandstone formations through which it travels along its 7.5-mile (12.1 km) length within the hills of t","link":"https://www.fhwa.dot.gov/byways","wiki":["Red Rock Scenic Byway","Arizona State Route 179"]},{"id":"san-juan-skyway","name":"San Juan Skyway","tier":"all-american","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"236 mi","lengthMi":236,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"The San Juan Skyway Scenic and Historic Byway is a 236-mile (380 km) All-American Road, National Forest Scenic Byway, and Colorado Scenic and Historic Byway located in Dolores, La Plata, Montezuma, San Juan, and San Miguel counties, Colorado, United States. The byway forms a loop in southwestern Colorado traversing the heart of the San Juan Mountains. The San Juan Skyway reaches its zenith at Red Mountain Pass at elevation 11,018 feet (3,358 m). Mesa Verde National Park was one of the original UNESCO World Heritage","link":"https://en.wikipedia.org/wiki/San_Juan_Skyway_Scenic_and_Historic_Byway","wiki":["San Juan Skyway","San Juan Skyway Scenic and Historic Byway"],"endpoints":{"from":"Durango, CO","to":"Durango, CO","via":["Silverton, CO","Ouray, CO","Telluride, CO","Cortez, CO"]}},{"id":"san-luis-obispo-north-coast-byway","name":"San Luis Obispo North Coast Byway","tier":"all-american","region":"West","regionLabel":"California","states":"California","sub":"California","length":"656 mi","lengthMi":656,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"State Route 1 (SR 1) is a major north–south state highway that runs along most of the Pacific coastline of the U.S. state of California. At 656 miles (1,056 km), it is the longest state route in California, and the second-longest in the US after Montana Highway 200. SR 1 has several portions designated as either Pacific Coast Highway (PCH), Cabrillo Highway, Shoreline Highway, or Coast Highway. Its southern terminus is at Interstate 5 (I-5) near Dana Point in Orange County and its northern terminus is at U.S. Route","link":"https://www.fhwa.dot.gov/byways","wiki":["San Luis Obispo North Coast Byway","California State Route 1"]},{"id":"scenic-byway-12","name":"Scenic Byway 12","tier":"all-american","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"123 mi","lengthMi":123,"lat":37.2108,"lng":-113.27,"approxLoc":false,"qualities":[],"blurb":"State Route 12 or Scenic Byway 12 (SR-12), also known as \"Highway 12 — A Journey Through Time Scenic Byway\", is a 123-mile-long (198 km) state highway designated an All-American Road located in Garfield County and Wayne County, Utah, United States.","link":"https://www.fhwa.dot.gov/byways","wiki":["Scenic Byway 12","Utah State Route 12"],"endpoints":{"from":"Bryce Canyon Junction, UT","to":"Boulder, UT","via":["Tropic Junction, UT","Cannonville, UT","Escalante, UT"]}},{"id":"selma-to-montgomery-march-byway","name":"Selma to Montgomery March Byway","tier":"all-american","region":"South","regionLabel":"Deep South","states":"Alabama","sub":"Alabama","length":"54 mi","lengthMi":54,"lat":32.8,"lng":-86.8,"approxLoc":true,"qualities":[],"blurb":"The Selma to Montgomery marches were three protest marches, held in 1965, along the 54-mile (87 km) highway from Selma, Alabama, to the state capital of Montgomery. The marches were organized by nonviolent activists to demonstrate the desire of African-American citizens to exercise their constitutional right to vote, in defiance of segregationist repression; they were part of a broader voting rights movement underway in Selma and throughout the American South. By highlighting racial injustice, they contributed to p","link":"https://en.wikipedia.org/wiki/Selma_to_Montgomery_marches","wiki":["Selma to Montgomery March Byway","Selma to Montgomery marches"]},{"id":"seward-highway","name":"Seward Highway","tier":"all-american","region":"Alaska","regionLabel":"Alaska","states":"Alaska","sub":"Alaska","length":"125 mi","lengthMi":125,"lat":61.1935,"lng":-149.8682,"approxLoc":false,"qualities":[],"blurb":"The Seward Highway is a highway in the U.S. state of Alaska that extends 125 miles (201 km) from Seward to Anchorage. It was completed in 1951 and runs through the scenic Kenai Peninsula, Chugach National Forest, Turnagain Arm, and Kenai Mountains. The Seward Highway is numbered Alaska Route 9 (AK-9) for the first 37 miles (60 km) from Seward to the Sterling Highway and AK-1 for the remaining distance to Anchorage. At the junction with the Sterling Highway, AK-1 turns west towards Sterling and Homer. About eight mi","link":"https://en.wikipedia.org/wiki/Seward_Highway","wiki":["Seward Highway","Seward Highway"],"endpoints":{"from":"Anchorage, AK","to":"Seward, AK"}},{"id":"trail-ridge-road","name":"Trail Ridge Road","tier":"all-american","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Rocky Mountain National Park","length":"48 mi","lengthMi":48,"lat":40.393,"lng":-105.68,"approxLoc":false,"qualities":["Scenic","Natural","Historic"],"blurb":"Trail Ridge Road is the highest continuous paved road in the United States, cresting at 12,183 feet as it crosses Rocky Mountain National Park between Estes Park and Grand Lake. Eleven miles of the route run above treeline through fragile alpine tundra, with pullouts overlooking the Never Summer Mountains and the headwaters of the Colorado River.","link":"https://www.nps.gov/romo/planyourvisit/trail_ridge_road.htm","wiki":["Trail Ridge Road","Rocky Mountain National Park","Never Summer Mountains"],"time":"~2 hrs","parkCode":"romo","season":"Late May – mid-October","mapCap":"Estes Park → Alpine Visitor Center → Grand Lake","planNote":"The high tundra section closes with the first heavy snows and reopens after Memorial Day plowing. Afternoon lightning is a real hazard above treeline — cross the exposed stretch in the morning, and stop at the Alpine Visitor Center for the highest facilities in the park.","film":[{"q":["Trail Ridge Road"],"cap":"Above the treeline on Trail Ridge"},{"q":["Forest Canyon"],"cap":"Forest Canyon overlook"},{"q":["Never Summer Mountains"],"cap":"The Never Summer Range"},{"q":["Rocky Mountain National Park"],"cap":"Alpine tundra at 12,000 ft"}],"highlights":[{"n":"Many Parks Curve","q":["Rocky Mountain National Park"],"d":"Sweeping view back over the valleys","lat":40.393,"lng":-105.62},{"n":"Forest Canyon Overlook","q":["Forest Canyon"],"d":"A glacial gorge from the tundra rim","lat":40.392,"lng":-105.69},{"n":"Alpine Visitor Center","q":["Alpine Visitor Center"],"d":"Highest visitor center in the NPS","lat":40.441,"lng":-105.754},{"n":"Milner Pass","q":["Milner Pass"],"d":"The Continental Divide at Poudre Lake","lat":40.421,"lng":-105.812}],"endpoints":{"from":"Estes Park, CO","to":"Grand Lake, CO"}},{"id":"volcanic-legacy-scenic-byway","name":"Volcanic Legacy Scenic Byway","tier":"all-american","region":"West","regionLabel":"California","states":"California · Oregon","sub":"California · Oregon","length":"500 mi","lengthMi":500,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"The Volcanic Legacy Scenic Byway is a scenic byway and All-American Road in the U.S. states of California and Oregon. It is roughly 500 miles (800 km) long and travels north–south along the Cascade Range past numerous volcanoes. It is composed of two separate National Scenic Byways, the Volcanic Legacy Scenic Byway - Oregon and Volcanic Legacy Scenic Byway - California. The former includes Rim Drive within Crater Lake National Park, while the latter wholly includes the Lassen Scenic Byway within Lassen Volcanic Nat","link":"https://www.fhwa.dot.gov/byways","wiki":["Volcanic Legacy Scenic Byway"]},{"id":"woodward-avenue","name":"Woodward Avenue","tier":"all-american","region":"Midwest","regionLabel":"Great Lakes","states":"Michigan","sub":"Michigan","length":"8 mi","lengthMi":8,"lat":44.3,"lng":-85.6,"approxLoc":true,"qualities":[],"blurb":"M-1, also known as Woodward Avenue, is a north–south state trunkline highway in the Metro Detroit area of the US state of Michigan. The highway, called \"Detroit's Main Street\", runs from Detroit north-northwesterly to Pontiac. It is one of the five principal avenues of Detroit, along with Michigan, Grand River, Gratiot, and Jefferson avenues. These streets were platted in 1805 by Judge Augustus B. Woodward, namesake to Woodward Avenue. The Federal Highway Administration (FHWA) has listed the highway as the Automoti","link":"https://en.wikipedia.org/wiki/M-1_(Michigan_highway)","wiki":["Woodward Avenue","M-1 (Michigan highway)"],"endpoints":{"from":"Detroit, MI","to":"Bloomfield Township, MI","via":["Highland Park, MI","Royal Oak, MI"]}},{"id":"going-to-the-sun","name":"Going-to-the-Sun Road","tier":"landmark","region":"Rockies","regionLabel":"Northern Rockies","states":"Montana","sub":"Glacier National Park","length":"50 mi","lengthMi":50,"time":"~2 hrs","lat":48.696,"lng":-113.718,"parkCode":"glac","approxLoc":false,"qualities":["Scenic","Natural","Historic"],"blurb":"A National Historic Landmark of engineering, Going-to-the-Sun Road threads 50 miles across the spine of Glacier National Park — from the forested shores of Lake McDonald, up the cliff-hung Garden Wall, over Logan Pass at 6,646 feet on the Continental Divide, and down to St. Mary Lake. Completed in 1932, it was the first road in the U.S. registered as a National Historic Civil Engineering Landmark. (It is a National Historic Landmark rather than an FHWA-designated byway.)","season":"Late June – mid-October","mapCap":"Lake McDonald → Logan Pass → St. Mary","planNote":"The alpine section over Logan Pass is only fully open from roughly late June to mid-October, weather permitting — plowing the Big Drift can take crews until late spring. Vehicle-reservation and timed-entry systems apply in peak season; start early and use the free park shuttle to skip the Logan Pass lot.","link":"https://www.nps.gov/glac/planyourvisit/goingtothesunroad.htm","wiki":["Going-to-the-Sun Road","Logan Pass","Saint Mary Lake"],"film":[{"q":["Lake McDonald"],"cap":"Lake McDonald — the western gateway"},{"q":["Going-to-the-Sun Road","Garden Wall (Montana)"],"cap":"The Garden Wall traverse"},{"q":["Logan Pass"],"cap":"Logan Pass on the Continental Divide"},{"q":["Saint Mary Lake","Wild Goose Island"],"cap":"Wild Goose Island, St. Mary Lake"},{"q":["Jackson Glacier"],"cap":"Jackson Glacier overlook"}],"highlights":[{"n":"Lake McDonald","q":["Lake McDonald"],"d":"Glacier's largest lake and the road's western start","lat":48.611,"lng":-113.876},{"n":"The Loop","q":["Going-to-the-Sun Road"],"d":"The single switchback climbing toward the pass","lat":48.762,"lng":-113.777},{"n":"Logan Pass","q":["Logan Pass"],"d":"6,646 ft on the Divide — wildflowers and goats","lat":48.696,"lng":-113.718},{"n":"Jackson Glacier Overlook","q":["Jackson Glacier"],"d":"The most visible glacier from the road","lat":48.669,"lng":-113.648},{"n":"Wild Goose Island","q":["Wild Goose Island","Saint Mary Lake"],"d":"The iconic islet on St. Mary Lake","lat":48.667,"lng":-113.573}],"endpoints":{"from":"West Glacier, MT","to":"St. Mary, MT"}},{"id":"alabama-s-coastal-connection","name":"Alabama's Coastal Connection","tier":"national-scenic-byway","region":"South","regionLabel":"Deep South","states":"Alabama","sub":"Alabama","length":"","lengthMi":null,"lat":32.8,"lng":-86.8,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Alabama's Coastal Connection"]},{"id":"amish-country-byway","name":"Amish Country Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Midwest","states":"Ohio","sub":"Ohio","length":"","lengthMi":null,"lat":40.3,"lng":-82.8,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Amish Country Byway"]},{"id":"arroyo-seco-parkway","name":"Arroyo Seco Parkway","tier":"national-scenic-byway","region":"West","regionLabel":"California","states":"California","sub":"California","length":"","lengthMi":null,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"The Arroyo Seco Parkway, also known as the Pasadena Freeway, is one of the oldest freeways in the United States. It connects Los Angeles with Pasadena alongside the Arroyo Seco seasonal river. Mostly opened in 1940, it represents the transitional phase between early parkways and later freeways. It conformed to modern standards when it was built, but is now regarded as a narrow, outdated roadway. A 1953 extension brought the south end to the Four Level Interchange in downtown Los Angeles and a connection with the re","link":"https://en.wikipedia.org/wiki/Arroyo_Seco_Parkway","wiki":["Arroyo Seco Parkway","Arroyo Seco Parkway"],"endpoints":{"from":"Los Angeles, CA","to":"Pasadena, CA","via":["South Pasadena, CA"]}},{"id":"ashley-river-road","name":"Ashley River Road","tier":"national-scenic-byway","region":"South","regionLabel":"Carolina Lowcountry","states":"South Carolina","sub":"South Carolina","length":"67 mi","lengthMi":67,"lat":32.8694,"lng":-80.0884,"approxLoc":false,"qualities":[],"blurb":"South Carolina Highway 61 (SC 61) is a 67-mile-long (108 km) state highway in the U.S. state of South Carolina. The highway is designated on a north–south direction, but physically travels in an east–west direction, from SC 30 in Charleston to U.S. Route 78 (US 78) near Branchville. The portion of SC 61 from Church Creek Bridge and 10 miles (16 km) north is designated a National Scenic Byway.","link":"https://www.fhwa.dot.gov/byways","wiki":["Ashley River Road","South Carolina Highway 61"],"endpoints":{"from":"Charleston, SC","to":"Whetstone Crossroads, SC","via":["Cooks Crossroads, SC","Givhans, SC","Canadys, SC"]}},{"id":"bayou-teche","name":"Bayou Teche","tier":"national-scenic-byway","region":"South","regionLabel":"Gulf Coast","states":"Louisiana","sub":"Louisiana","length":"125 mi","lengthMi":125,"lat":31,"lng":-92,"approxLoc":true,"qualities":[],"blurb":"Bayou Teche ()(Louisiana French: Bayou Têche) is a 125-mile-long (201 km) waterway in south central Louisiana in the United States. Bayou Teche was the Mississippi River's main course when it developed a delta about 2,800 to 4,500 years ago. Through a natural process known as deltaic switching, the river's deposits of silt and sediment cause the Mississippi to change its course every thousand years or so.","link":"https://en.wikipedia.org/wiki/Bayou_Teche","wiki":["Bayou Teche","Bayou Teche"]},{"id":"big-bend-scenic-byway","name":"Big Bend Scenic Byway","tier":"national-scenic-byway","region":"South","regionLabel":"Florida","states":"Florida","sub":"Florida","length":"","lengthMi":null,"lat":28.6,"lng":-81.5,"approxLoc":true,"qualities":[],"blurb":"Big Bend generally refers to a major change in course or large meander in a river. It may refer to:","link":"https://en.wikipedia.org/wiki/Big_Bend","wiki":["Big Bend Scenic Byway","Big Bend"]},{"id":"billy-the-kid-scenic-byway","name":"Billy the Kid Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"New Mexico","sub":"New Mexico","length":"","lengthMi":null,"lat":35.6876,"lng":-105.9409,"approxLoc":false,"qualities":[],"blurb":"Henry McCarty (September 17 or November 23, 1859 – July 14, 1881), alias William H. Bonney, better known as Billy the Kid, was an American outlaw and gunfighter of the Old West who was linked to nine murders. He was solely responsible for four of them, and he may have played a role in five, alongside other men. He is also noted for his involvement in New Mexico's Lincoln County War. McCarty was orphaned at the age of 15. His first arrest was for stealing food at the age of 16 in 1875. Ten days later, he robbed a Ch","link":"https://en.wikipedia.org/wiki/Billy_the_Kid","wiki":["Billy the Kid Scenic Byway","Billy the Kid"]},{"id":"brandywine-valley-scenic-byway","name":"Brandywine Valley Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"Delaware","sub":"Delaware","length":"","lengthMi":null,"lat":39,"lng":-75.5,"approxLoc":true,"qualities":[],"blurb":"The Delaware Byways (formerly Delaware Scenic and Historic Highways) system consists of roads in the U.S. state of Delaware that travel through areas of scenic and historic interest. The intent of this system is to promote tourism and raise awareness of the communities along these routes.","link":"https://en.wikipedia.org/wiki/List_of_Delaware_Byways","wiki":["Brandywine Valley Scenic Byway","List of Delaware Byways"]},{"id":"cascade-lakes-scenic-byway","name":"Cascade Lakes Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"66 mi","lengthMi":66,"lat":44.0416,"lng":-121.3331,"approxLoc":false,"qualities":[],"blurb":"The Cascades Lakes Scenic Byway (Forest Route 46) is a National Scenic Byway in central Oregon in the United States. It runs for 66 miles (106 km) in the rugged country of Deschutes and Klamath counties on the east side of the Cascade Range. It offers particularly good views of Mount Bachelor, Broken Top, and the Three Sisters (Oregon) mountains and provides access to many recreational facilities in central Oregon. The route is so named because it weaves past a number of small natural lakes along the Cascades as we","link":"https://www.fhwa.dot.gov/byways","wiki":["Cascade Lakes Scenic Byway"]},{"id":"cascade-loop","name":"Cascade Loop","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Washington","sub":"Washington","length":"440 mi","lengthMi":440,"lat":46.6138,"lng":-120.5564,"approxLoc":false,"qualities":[],"blurb":"The Cascade Loop Scenic Byway is a 440-mile-long (710 km) National Scenic Byway and Washington State Scenic and Recreational Highway encircling the North Cascades in the U.S. state of Washington. It follows eight different numbered highways: US 2 from Everett to Sunnyslope; US 97 Alternate from Sunnyslope to Chelan; US 97 from Chelan to Pateros; SR 153 from Pateros to Twisp; SR 20 from Twisp to Coupeville; SR 525 from Coupeville to Mukilteo; SR 526 from Mukilteo to Everett; and I-5 in Everett","link":"https://www.fhwa.dot.gov/byways","wiki":["Cascade Loop","Cascade Loop Scenic Byway"]},{"id":"cherohala-skyway","name":"Cherohala Skyway","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachians","states":"North Carolina · Tennessee","sub":"North Carolina · Tennessee","length":"43 mi","lengthMi":43,"lat":35.3211,"lng":-83.9767,"approxLoc":false,"qualities":[],"blurb":"The Cherohala Skyway is a 43-mile (69 km) National Scenic Byway and National Forest Scenic Byway that connects Tellico Plains, Tennessee, to Robbinsville, North Carolina, in the southeastern United States. Its name is a portmanteau of Cherokee and Nantahala, the two national forests through which it passes. Along with multiple vistas and overlooks, the skyway provides easy vehicular access to various protected and recreational areas of the Unicoi Mountains, including the Citico Creek Wilderness, the Bald River Gorg","link":"https://www.fhwa.dot.gov/byways","wiki":["Cherohala Skyway"]},{"id":"cherokee-foothills-scenic-highway","name":"Cherokee Foothills Scenic Highway","tier":"national-scenic-byway","region":"South","regionLabel":"Carolina Lowcountry","states":"South Carolina","sub":"South Carolina","length":"120 mi","lengthMi":120,"lat":35.1229,"lng":-82.1406,"approxLoc":false,"qualities":[],"blurb":"South Carolina Highway 11 (SC 11), also known as the Cherokee Foothills Scenic Highway, is a 119.850-mile (192.880 km) state highway through the far northern part of the U.S. state of South Carolina, following the southernmost peaks of the Blue Ridge Mountains. The route is surrounded by peach orchards, quaint villages, and parks. It is an alternative to Interstate 85 (I-85) and has been featured by such publications as National Geographic, Rand McNally, and Southern Living.","link":"https://www.fhwa.dot.gov/byways","wiki":["Cherokee Foothills Scenic Highway","South Carolina Highway 11"],"endpoints":{"from":"West Union, SC","to":"Gaffney, SC","via":["Cleveland, SC","Gowensville, SC","New Prospect, SC"]}},{"id":"coal-heritage-trail","name":"Coal Heritage Trail","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachia","states":"West Virginia","sub":"West Virginia","length":"","lengthMi":null,"lat":37.5789,"lng":-81.3779,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Coal Heritage Trail"]},{"id":"colorado-river-headwaters-byway","name":"Colorado River Headwaters Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Colorado River Headwaters Byway"]},{"id":"connecticut-river-byway","name":"Connecticut River Byway","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Vermont","sub":"Vermont","length":"406 mi","lengthMi":406,"lat":44.1,"lng":-72.7,"approxLoc":true,"qualities":[],"blurb":"The Connecticut River is a major river in the New England region of the United States. The region's longest, it flows roughly southward for 406 miles (653 km) through four states. Rising 300 yards (270 m) south of the U.S. border with Quebec, Canada, it discharges into Long Island Sound between Old Saybrook and Old Lyme, Connecticut. Its watershed encompasses 11,260 square miles (29,200 km2), covering parts of five U.S. states and one Canadian province, composed of 148 tributaries, 38 of which are major rivers. It ","link":"https://en.wikipedia.org/wiki/Connecticut_River","wiki":["Connecticut River Byway","Connecticut River"]},{"id":"connecticut-route-169","name":"Connecticut Route 169","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Connecticut","sub":"Connecticut","length":"47 mi","lengthMi":47,"lat":41.6,"lng":-72.7,"approxLoc":true,"qualities":[],"blurb":"Route 169 is a 47.36-mile-long (76.22 km) state highway in Connecticut and Massachusetts, United States. It begins in the city of Norwich, Connecticut, and runs 38 miles (61 km) through Northeastern Connecticut, continuing across the state border into Southbridge, Massachusetts. The route ends in Charlton after another nine miles (14 km). A portion of the route in the town center of Pomfret is on the National Register of Historic Places as Pomfret Street Historic District, and 32.10 miles (51.66 km) of the road is ","link":"https://www.fhwa.dot.gov/byways","wiki":["Connecticut Route 169","Route 169 (Connecticut–Massachusetts)"],"endpoints":{"from":"Norwich, CT","to":"Charlton, CT","via":["Canterbury, CT","Pomfret, CT","Southbridge, CT"]}},{"id":"copper-country-trail","name":"Copper Country Trail","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Great Lakes","states":"Michigan","sub":"Michigan","length":"279 mi","lengthMi":279,"lat":44.3,"lng":-85.6,"approxLoc":true,"qualities":[],"blurb":"US Highway 41 (US 41) is a part of the United States Numbered Highway System that runs from Miami, Florida, to the Upper Peninsula of the US state of Michigan. In Michigan, it is a state trunkline highway that enters the state via the Interstate Bridge between Marinette, Wisconsin, and Menominee, Michigan. The 278.769 miles (448.635 km) of US 41 that lie within Michigan serve as a major conduit. Most of the highway is listed on the National Highway System. Various sections are rural two-lane highway, urbanized four","link":"https://en.wikipedia.org/wiki/U.S._Route_41_in_Michigan","wiki":["Copper Country Trail","U.S. Route 41 in Michigan"],"endpoints":{"from":"Menominee River, MI","to":"Copper Harbor, MI","via":["Gladstone, MI","Negaunee Township, MI","Calumet, MI"]}},{"id":"coronado-trail-scenic-road","name":"Coronado Trail Scenic Road","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"Arizona","sub":"Arizona","length":"","lengthMi":null,"lat":34.8796,"lng":-111.7687,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Coronado Trail Scenic Road"]},{"id":"country-music-highway","name":"Country Music Highway","tier":"national-scenic-byway","region":"South","regionLabel":"Appalachia","states":"Kentucky","sub":"Kentucky","length":"158 mi","lengthMi":158,"lat":37.5,"lng":-85.3,"approxLoc":true,"qualities":[],"blurb":"U.S. Route 23 (US 23) is a 157.765-mile-long (253.898 km) United States Numbered Highway in the state of Kentucky. It travels from the Virginia state line near Jenkins to the Ohio state line west of South Shore via Jenkins, Pikeville, Coal Run Village, Prestonsburg, Paintsville, Louisa, Catlettsburg, Ashland, Russell, Flatwoods, Raceland, Wurtland, Greenup, and South Shore.","link":"https://en.wikipedia.org/wiki/U.S._Route_23_in_Kentucky","wiki":["Country Music Highway","U.S. Route 23 in Kentucky"],"endpoints":{"from":"Pound Gap, KY","to":"Ohio River, KY","via":["Allen, KY","Ashland, KY","Greenup, KY"]}},{"id":"crowley-s-ridge-parkway","name":"Crowley's Ridge Parkway","tier":"national-scenic-byway","region":"South","regionLabel":"Ozarks","states":"Arkansas","sub":"Arkansas","length":"212 mi","lengthMi":212,"lat":34.9,"lng":-92.4,"approxLoc":true,"qualities":[],"blurb":"Crowley's Ridge Parkway is a 212.0-mile-long (341.2 km) National Scenic Byway in northeast Arkansas and the Missouri Bootheel along Crowley's Ridge in the United States. Motorists can access the parkway from US Route 49 (US 49) at its southern terminus near the Helena Bridge over the Mississippi River outside Helena-West Helena, Arkansas, or from Missouri Route 25 (Route 25) near Kennett, Missouri. The parkway runs along Crowley's Ridge, a unique geological formation, and also parts of the St. Francis National Fore","link":"https://www.fhwa.dot.gov/byways","wiki":["Crowley's Ridge Parkway"],"endpoints":{"from":"Mississippi River, AR","to":"Malden, AR","via":["Wynne, AR","Oak Grove Heights, AR","St. Francis River, AR"]}},{"id":"death-valley-scenic-byway","name":"Death Valley Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"California","states":"California","sub":"California","length":"43 mi","lengthMi":43,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"State Route 190 (SR 190) is a state highway in the U.S. state of California that is split into two parts by the Sierra Nevada. The western portion begins at Tipton at a junction with State Route 99 and heads east towards Porterville before ending at Quaking Aspen in the Sequoia National Forest. The eastern portion begins at US 395 southeast of Olancha, heads east through Death Valley National Park, and ends at State Route 127 at Death Valley Junction. The 43.0-mile (69.2 km) portion over the Sierra Nevada remains u","link":"https://en.wikipedia.org/wiki/California_State_Route_190","wiki":["Death Valley Scenic Byway","California State Route 190"]},{"id":"delaware-bayshore-byway","name":"Delaware Bayshore Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"Delaware","sub":"Delaware","length":"","lengthMi":null,"lat":39,"lng":-75.5,"approxLoc":true,"qualities":[],"blurb":"The Delaware Byways (formerly Delaware Scenic and Historic Highways) system consists of roads in the U.S. state of Delaware that travel through areas of scenic and historic interest. The intent of this system is to promote tourism and raise awareness of the communities along these routes.","link":"https://en.wikipedia.org/wiki/List_of_Delaware_Byways","wiki":["Delaware Bayshore Byway","List of Delaware Byways"]},{"id":"delaware-river-scenic-byway","name":"Delaware River Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"New Jersey","sub":"New Jersey","length":"35 mi","lengthMi":35,"lat":40.6391,"lng":-75.1935,"approxLoc":false,"qualities":[],"blurb":"Route 29 is a state highway in the U.S. state of New Jersey. Signed north-south, it runs 34.76 miles (55.94 km) from an interchange with Interstate 295 (I-295) in Hamilton Township in Mercer County, where the road continues east as I-195, northwest to Route 12 (Bridge Street / Race Street) in Frenchtown, Hunterdon County. Between the southern terminus and I-295 in Ewing Township, the route is a mix of expressway and boulevard that runs along the Delaware River through Trenton. This section includes a truck-restrict","link":"https://www.fhwa.dot.gov/byways","wiki":["Delaware River Scenic Byway","New Jersey Route 29"],"endpoints":{"from":"Hamilton Township, NJ","to":"Frenchtown, NJ","via":["Ewing Township, NJ","Lambertville, NJ","Stockton, NJ"]}},{"id":"dinosaur-diamond-prehistoric-highway","name":"Dinosaur Diamond Prehistoric Highway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"486 mi","lengthMi":486,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"The Dinosaur Diamond is a 486-mile (782 km) scenic and historic byway loop through the dinosaur fossil laden Uinta Basin of the U.S. states of Utah and Colorado. The byway comprises the following two National Scenic Byways: The 328-mile (528 km) Dinosaur Diamond Prehistoric Highway in Carbon, Duchesne, Emery, and Grand counties, Utah; and The 134-mile (216 km) Dinosaur Diamond National Scenic Byway in Garfield, Mesa, Moffat, and Rio Blanco counties, Colorado. The highway forms a diamond-shaped loop with vertices at","link":"https://en.wikipedia.org/wiki/Dinosaur_Diamond","wiki":["Dinosaur Diamond Prehistoric Highway","Dinosaur Diamond"]},{"id":"door-county-coastal-byway","name":"Door County Coastal Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Great Lakes","states":"Wisconsin","sub":"Wisconsin","length":"","lengthMi":null,"lat":44.6,"lng":-89.9,"approxLoc":true,"qualities":[],"blurb":"The Wisconsin Scenic Byways are a system consisting of roads in the U.S. state of Wisconsin that travel through areas of scenic and historic interest. The intent of this system is to promote tourism and raise awareness of the communities along these routes. Wisconsin also has another system of scenic highways called Rustic Roads. There are five state-recognized scenic byways in Wisconsin, and three of them have also been designated National Scenic Byways.","link":"https://www.fhwa.dot.gov/byways","wiki":["Door County Coastal Byway","List of Wisconsin Scenic Byways"]},{"id":"east-tennessee-crossing","name":"East Tennessee Crossing","tier":"national-scenic-byway","region":"South","regionLabel":"Appalachia","states":"Tennessee","sub":"Tennessee","length":"","lengthMi":null,"lat":35.2018,"lng":-84.8427,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["East Tennessee Crossing"],"endpoints":{"from":"Cherokee National Forest, TN","to":"Cumberland Gap National Historical Park, TN","via":["Leadvale, TN","Thorn Hill, TN","Cumberland Gap, TN"]}},{"id":"ebbetts-pass","name":"Ebbetts Pass","tier":"national-scenic-byway","region":"West","regionLabel":"California","states":"California","sub":"California","length":"2650 mi","lengthMi":2650,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"Ebbetts Pass (el. 8,736 ft or 2,663 m), named after John Ebbetts, is a high mountain pass through the Sierra Nevada range in Alpine County, California. Ebbetts is the eastern of two passes in the area traversed by State Route 4. The western pass is the Pacific Grade Summit (el 8,050 ft or 2,450 m). The pass is registered as a California Historical Landmark. The Pacific Crest Trail, a 2,650-mile (4,260 km) long National Scenic Trail crosses State Route 4 at Ebbetts Pass.","link":"https://en.wikipedia.org/wiki/Ebbetts_Pass","wiki":["Ebbetts Pass","Ebbetts Pass"]},{"id":"edge-of-the-wilderness","name":"Edge of the Wilderness","tier":"national-scenic-byway","region":"Midwest","regionLabel":"North Woods","states":"Minnesota","sub":"Minnesota","length":"47 mi","lengthMi":47,"lat":46.3,"lng":-94.3,"approxLoc":true,"qualities":[],"blurb":"Minnesota State Highway 38 (MN 38) is a 46.766-mile-long (75.263 km) highway in north-central Minnesota, which runs from its intersection with U.S. Highway 2 in Grand Rapids and continues north to its northern terminus at its intersection with State Highway 1 in Effie. The entire length of Highway 38 has been designated a National Scenic Byway under the name Edge of the Wilderness. It is also sometimes called the Northwoods Highway.","link":"https://en.wikipedia.org/wiki/Minnesota_State_Highway_38","wiki":["Edge of the Wilderness","Minnesota State Highway 38"],"endpoints":{"from":"Grand Rapids, MN","to":"Effie, MN","via":["Marcell, MN"]}},{"id":"el-camino-real","name":"El Camino Real","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"New Mexico","sub":"New Mexico","length":"","lengthMi":null,"lat":34.0675,"lng":-106.8988,"approxLoc":false,"qualities":[],"blurb":"El Camino Real (Spanish; \"The Royal Road\" or \"The King's Highway\") may refer to:","link":"https://en.wikipedia.org/wiki/El_Camino_Real","wiki":["El Camino Real","El Camino Real"]},{"id":"flaming-gorge-uintas-scenic-byway","name":"Flaming Gorge-Uintas Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"80 mi","lengthMi":80,"lat":39.3,"lng":-111.7,"approxLoc":true,"qualities":[],"blurb":"The Flaming Gorge - Uintas Scenic Byway is a National Scenic Byway in the state of Utah. It spans approximately 80 miles (130 km) as it travels from Vernal, Utah northward through the Ashley National Forest and the Uintah Mountains to the area around Flaming Gorge National Recreation Area in the northeastern corner of the state.","link":"https://en.wikipedia.org/wiki/Flaming_Gorge-Uintas_Scenic_Byway","wiki":["Flaming Gorge-Uintas Scenic Byway","Flaming Gorge-Uintas Scenic Byway"],"endpoints":{"from":"Vernal, UT","to":"Greendale Junction, UT","via":[]}},{"id":"flint-hills-scenic-byway","name":"Flint Hills Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Great Plains","states":"Kansas","sub":"Kansas","length":"103 mi","lengthMi":103,"lat":38.5,"lng":-98.4,"approxLoc":true,"qualities":[],"blurb":"K-177 is a 102.871-mile-long (165.555 km) south–north state highway in central Kansas. It runs from U.S. Route 54 (US-54) near El Dorado northward to US-24 in Manhattan, passing through the Flint Hills. It is part of the Flint Hills Scenic Byway and the Prairie Parkway.","link":"https://www.fhwa.dot.gov/byways","wiki":["Flint Hills Scenic Byway","K-177 (Kansas highway)"],"endpoints":{"from":"Cassoday, KS","to":"Manhattan, KS","via":["Strong City, KS","Council Grove, KS"]}},{"id":"frontier-pathways-scenic-byway","name":"Frontier Pathways Scenic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"103 mi","lengthMi":103,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"The Frontier Pathways is a 103-mile (166 km) National Scenic Byway and Colorado Scenic and Historic Byway located in Custer and Pueblo counties, Colorado, US.","link":"https://en.wikipedia.org/wiki/Frontier_Pathways_Scenic_and_Historic_Byway","wiki":["Frontier Pathways Scenic Byway","Frontier Pathways Scenic and Historic Byway"]},{"id":"george-parks-highway","name":"George Parks Highway","tier":"national-scenic-byway","region":"Alaska","regionLabel":"Alaska","states":"Alaska","sub":"Alaska","length":"323 mi","lengthMi":323,"lat":63.0141,"lng":-149.5909,"approxLoc":false,"qualities":[],"blurb":"The George Parks Highway (numbered Interstate A-4 and signed Alaska Route 3), usually called simply the Parks Highway, runs 323 miles (520 km) from the Glenn Highway 35 miles (56 km) north of Anchorage to Fairbanks in the Alaska Interior. The highway, originally known as the Anchorage-Fairbanks Highway, was completed in 1971, and given its current name in 1975. The highway, which mostly parallels the Alaska Railroad, is one of the most important roads in Alaska. It is the main route between Anchorage and Fairbanks ","link":"https://en.wikipedia.org/wiki/George_Parks_Highway","wiki":["George Parks Highway","George Parks Highway"],"endpoints":{"from":"Gateway, AK","to":"Fairbanks, AK","via":["Wasilla, AK","Denali State Park, AK","Denali National Park and Preserve, AK"]}},{"id":"glenn-highway","name":"Glenn Highway","tier":"national-scenic-byway","region":"Alaska","regionLabel":"Alaska","states":"Alaska","sub":"Alaska","length":"179 mi","lengthMi":179,"lat":61.2213,"lng":-149.8073,"approxLoc":false,"qualities":[],"blurb":"The Glenn Highway (part of Alaska Route 1) is a highway in the U.S. state of Alaska, extending 179 miles (288 km) from Anchorage near Merrill Field to Glennallen on the Richardson Highway. The Tok Cut-Off is often considered part of the Glenn Highway, for a total length of 328 miles (528 km).","link":"https://en.wikipedia.org/wiki/Glenn_Highway","wiki":["Glenn Highway","Glenn Highway"],"endpoints":{"from":"Municipality of Anchorage, AK","to":"Glennallen, AK","via":["Knik River, AK","Gateway, AK","Palmer, AK"]}},{"id":"gold-belt-tour-scenic-byway","name":"Gold Belt Tour Scenic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Gold Belt Tour Scenic Byway"]},{"id":"grand-mesa-scenic-byway","name":"Grand Mesa Scenic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"State Highway 65 (SH 65) is a state highway in Colorado that crosses the Grand Mesa. The highway along with a road to Lands End Overlook were designated as the Grand Mesa National Scenic Byway in 1996. SH 65's southern terminus is at SH 92 east of Delta, and its northern terminus is at Interstate 70 (I-70) and U.S. Route 6 (US 6) northeast of Palisade.","link":"https://en.wikipedia.org/wiki/Colorado_State_Highway_65","wiki":["Grand Mesa Scenic Byway","Colorado State Highway 65"],"endpoints":{"from":"Saunders, CO","to":"Cedaredge, CO","via":[]}},{"id":"gunflint-trail","name":"Gunflint Trail","tier":"national-scenic-byway","region":"Midwest","regionLabel":"North Woods","states":"Minnesota","sub":"Minnesota","length":"57 mi","lengthMi":57,"lat":46.3,"lng":-94.3,"approxLoc":true,"qualities":[],"blurb":"County State-Aid Highway 12 (CSAH 12), also known as the Gunflint Trail, or County Road 12 (CR 12), is a 57-mile (92 km) paved roadway and National Scenic Byway in Cook County, Minnesota, that begins in Grand Marais and ends at Saganaga Lake in the Boundary Waters Canoe Area Wilderness (BWCAW), near the U.S. border with Ontario. It provides access to many of the entry points in the BWCAW.","link":"https://en.wikipedia.org/wiki/County_State-Aid_Highway_12_(Cook_County%2C_Minnesota)","wiki":["Gunflint Trail","County State-Aid Highway 12 (Cook County, Minnesota)"]},{"id":"haines-highway","name":"Haines Highway","tier":"national-scenic-byway","region":"Alaska","regionLabel":"Alaska","states":"Alaska","sub":"Alaska","length":"110 mi","lengthMi":110,"lat":59.2344,"lng":-135.4565,"approxLoc":false,"qualities":[],"blurb":"The Haines Highway or Haines Cut-Off (and still often called Haines Road) is a highway that connects Haines, Alaska, in the United States, with Haines Junction, Yukon, Canada, passing through the province of British Columbia. It follows the route of the old Dalton Trail from the port of Haines inland for about 180 kilometres (110 miles) to Klukshu, Yukon, and then continues to Haines Junction. The highway is about 244 km (152 mi) long, of which 45 miles (72 km) is in Alaska. The highway was known as \"Yukon Highway ","link":"https://en.wikipedia.org/wiki/Haines_Highway","wiki":["Haines Highway","Haines Highway"],"endpoints":{"from":"Haines, AK","to":"Haines Junction, AK","via":["Dalton Cache–Pleasant Camp Border Crossing, AK"]}},{"id":"highland-scenic-highway","name":"Highland Scenic Highway","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachia","states":"West Virginia","sub":"West Virginia","length":"23 mi","lengthMi":23,"lat":38.311,"lng":-80.1255,"approxLoc":false,"qualities":[],"blurb":"West Virginia Route 150 is a 22.5-mile (36.2 km) long north–south scenic state highway in the Marlinton and Gauley Ranger Districts of the Monongahela National Forest in southeast West Virginia. The southern terminus of the route is at West Virginia Route 39 and West Virginia Route 55 northwest of Mill Point. The northern terminus is at U.S. Route 219 and WV 55 north of Edray, near Marlinton.","link":"https://www.fhwa.dot.gov/byways","wiki":["Highland Scenic Highway","West Virginia Route 150"]},{"id":"historic-bluff-country","name":"Historic Bluff Country","tier":"national-scenic-byway","region":"Midwest","regionLabel":"North Woods","states":"Minnesota","sub":"Minnesota","length":"88 mi","lengthMi":88,"lat":43.8188,"lng":-91.2737,"approxLoc":false,"qualities":[],"blurb":"Minnesota State Highway 16 (MN 16) is an 87.671-mile-long (141.093 km) two-lane highway in southeast Minnesota, which runs from its interchange with Interstate Highway 90 in Dexter and continues east to its eastern terminus at the Wisconsin state line concurrent with U.S. Highways 14 and 61 outside La Crescent just west of La Crosse, Wisconsin. The route was designated as a National Scenic Byway in 2003 as the Historic Bluff Country Scenic Byway. The roadway follows the route of old U.S. Highway 16.","link":"https://en.wikipedia.org/wiki/Minnesota_State_Highway_16","wiki":["Historic Bluff Country","Minnesota State Highway 16"],"endpoints":{"from":"Dexter, MN","to":"Mississippi River, MN","via":["Fountain Township, MN","Rushford Village, MN","La Crescent Township, MN"]}},{"id":"hocking-hills-scenic-byway","name":"Hocking Hills Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Midwest","states":"Ohio","sub":"Ohio","length":"","lengthMi":null,"lat":39.4317,"lng":-82.5382,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Hocking Hills Scenic Byway"]},{"id":"indian-river-lagoon","name":"Indian River Lagoon","tier":"national-scenic-byway","region":"South","regionLabel":"Florida","states":"Florida","sub":"Florida","length":"5 mi","lengthMi":5,"lat":28.6,"lng":-81.5,"approxLoc":true,"qualities":[],"blurb":"The Indian River Lagoon is a grouping of three lagoons: the Mosquito Lagoon, the Banana River, and the Indian River, on the Atlantic Coast of Florida; one of the most biodiverse estuaries in the Northern Hemisphere and is home to more than 4,300 species of plants and animals. The Lagoon contains five state parks, four federal wildlife refuges and a national seashore. The Lagoon varies in width from 0.5 to 5 miles (0.80 to 8.05 km) and averages 4 feet (1.2 m) in depth.","link":"https://en.wikipedia.org/wiki/Indian_River_Lagoon","wiki":["Indian River Lagoon","Indian River Lagoon"]},{"id":"jemez-mountain-trail","name":"Jemez Mountain Trail","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"New Mexico","sub":"New Mexico","length":"68 mi","lengthMi":68,"lat":34.5,"lng":-106.1,"approxLoc":true,"qualities":[],"blurb":"New Mexico State Road 4 (NM 4) is a 67.946-mile-long (109.348 km) state highway in Sandoval, Los Alamos, and Santa Fe counties in New Mexico, United States. It is significant as the main access route (in conjunction with NM 501 and NM 502) connecting the remote town of Los Alamos, Los Alamos National Laboratory, and Bandelier National Monument to other, more major highways in New Mexico.","link":"https://en.wikipedia.org/wiki/New_Mexico_State_Road_4","wiki":["Jemez Mountain Trail","New Mexico State Road 4"],"endpoints":{"from":"San Ysidro, NM","to":"La Cueva, NM","via":["Jemez Pueblo, NM"]}},{"id":"journey-through-hallowed-ground","name":"Journey Through Hallowed Ground","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"Maryland","sub":"Maryland","length":"","lengthMi":null,"lat":39,"lng":-76.8,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Journey Through Hallowed Ground"]},{"id":"kaibab-plateau-north-rim-parkway","name":"Kaibab Plateau-North Rim Parkway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"Arizona","sub":"Arizona","length":"43 mi","lengthMi":43,"lat":34.3,"lng":-111.7,"approxLoc":true,"qualities":[],"blurb":"State Route 67 (SR 67) is a 43.4-mile-long (69.8 km), north–south state highway in northern Arizona. Also called the Kaibab Plateau – North Rim Parkway, SR 67 is the sole road that links U.S. Route 89A (US 89A) at Jacob Lake to the North Rim of Grand Canyon National Park. Along the route, the road heads through the national park as well as Kaibab National Forest and traverses extensive coniferous forests. The section inside the national park is maintained by the National Park Service (NPS), whereas the section nort","link":"https://www.fhwa.dot.gov/byways","wiki":["Kaibab Plateau-North Rim Parkway","Arizona State Route 67"],"endpoints":{"from":"Jacob Lake, AZ","to":"Grand Canyon NP, AZ","via":[]}},{"id":"kancamagus-scenic-byway","name":"Kancamagus Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"White Mountains","states":"New Hampshire","sub":"New Hampshire","length":"56 mi","lengthMi":56,"lat":44.0111,"lng":-71.479,"approxLoc":false,"qualities":[],"blurb":"New Hampshire Route 112 (NH 112) is a 56.39-mile-long (90.75 km) east–west state highway in northern New Hampshire. The highway winds across the state, connecting Bath to Conway through the heart of the scenic and mountainous White Mountain National Forest. The eastern portion of NH 112 is known as the Kancamagus Highway, running 32 miles (51 km) through the White Mountains from Lincoln to Conway. 26.5 miles (42.6 km) of the highway have been designated a National Scenic Byway by the United States Department of Tra","link":"https://www.fhwa.dot.gov/byways","wiki":["Kancamagus Scenic Byway","New Hampshire Route 112"],"endpoints":{"from":"Lincoln, NH","to":"Conway, NH"}},{"id":"katahdin-woods-and-waters-scenic-byway","name":"Katahdin Woods and Waters Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Maine Coast","states":"Maine","sub":"Maine","length":"","lengthMi":null,"lat":45.4,"lng":-69.2,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Katahdin Woods and Waters Scenic Byway"]},{"id":"lake-tahoe-eastshore-drive","name":"Lake Tahoe-Eastshore Drive","tier":"national-scenic-byway","region":"West","regionLabel":"Great Basin","states":"Nevada","sub":"Nevada","length":"","lengthMi":null,"lat":39.2495,"lng":-119.9897,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Lake Tahoe-Eastshore Drive"],"endpoints":{"from":"City of Carson City0.00–3.95, NV","to":"Crystal Bay, NV","via":["Incline Village, NV"]}},{"id":"lariat-loop","name":"Lariat Loop","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Lariat Loop"],"endpoints":{"from":"El Rancho, CO","to":"Golden, CO","via":["Morrison, CO"]}},{"id":"lincoln-highway","name":"Lincoln Highway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Midwest","states":"Illinois · Iowa · Nebraska","sub":"Illinois · Iowa","length":"","lengthMi":null,"lat":40,"lng":-89.2,"approxLoc":true,"qualities":[],"blurb":"The Lincoln Highway is one of the first transcontinental highways in the United States and one of the first highways designed expressly for automobiles. Conceived in 1912 by Indiana entrepreneur Carl G. Fisher, and formally dedicated October 31, 1913, the Lincoln Highway runs coast-to-coast from Times Square in New York City west to Lincoln Park in San Francisco. The full route originally ran through 13 states: New York, New Jersey, Pennsylvania, Ohio, Indiana, Illinois, Iowa, Nebraska, Colorado, Wyoming, Utah, Nev","link":"https://en.wikipedia.org/wiki/Lincoln_Highway","wiki":["Lincoln Highway","Lincoln Highway"]},{"id":"loess-hills-scenic-byway","name":"Loess Hills Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Great Plains","states":"Iowa","sub":"Iowa","length":"","lengthMi":null,"lat":42,"lng":-93.5,"approxLoc":true,"qualities":[],"blurb":"The Loess Hills are a formation of wind-deposited loess soil in the westernmost parts of Iowa and Missouri, and the easternmost parts of Nebraska and Kansas, along the Missouri River.","link":"https://en.wikipedia.org/wiki/Loess_Hills","wiki":["Loess Hills Scenic Byway","Loess Hills"]},{"id":"logan-canyon-scenic-byway","name":"Logan Canyon Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"","lengthMi":null,"lat":41.7431,"lng":-111.7878,"approxLoc":false,"qualities":[],"blurb":"Logan Canyon is a canyon in the western United States in northeastern Utah, which cuts its way through the Bear River Mountains, a branch of the Wasatch Range. It is popular for both summer and winter activities, especially rock-climbing, hiking, camping, fishing, snowmobiling, and skiing, at the Beaver Mountain ski resort. The canyon rises to an elevation of approximately 7,800 feet (2,400 m) above sea level, after a vertical climb of about 2,900 feet (880 m). Just beyond the summit is a steep road leading into Be","link":"https://en.wikipedia.org/wiki/Logan_Canyon","wiki":["Logan Canyon Scenic Byway","Logan Canyon"]},{"id":"mckenzie-pass-santiam-pass-scenic-byway","name":"McKenzie Pass-Santiam Pass Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"82 mi","lengthMi":82,"lat":44,"lng":-120.6,"approxLoc":true,"qualities":[],"blurb":"The McKenzie Pass–Santiam Pass Scenic Byway is an 82-mile-long (132 km) National Scenic Byway in the U.S. state of Oregon. The route is a loop designed to provide a tour of the high Cascade Range northwest of Bend, passing over both McKenzie Pass and Santiam Pass.","link":"https://www.fhwa.dot.gov/byways","wiki":["McKenzie Pass-Santiam Pass Scenic Byway","McKenzie Pass–Santiam Pass Scenic Byway"]},{"id":"merritt-parkway","name":"Merritt Parkway","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Connecticut","sub":"Connecticut","length":"","lengthMi":null,"lat":41.6,"lng":-72.7,"approxLoc":true,"qualities":[],"blurb":"The Merritt Parkway (also known locally as \"The Merritt\") is a controlled-access parkway in Fairfield County, Connecticut, with a small section at the northern end in New Haven County. Designed for Connecticut's Gold Coast, the parkway is known for its scenic layout, its uniquely styled signage, and the architecturally elaborate overpasses along the route. As one of the first, oldest parkways in the United States, it is designated as a National Scenic Byway and is also listed in the National Register of Historic Pl","link":"https://www.fhwa.dot.gov/byways","wiki":["Merritt Parkway"],"endpoints":{"from":"Greenwich, CT","to":"Milford, CT","via":["New Canaan, CT","Westport, CT","Trumbull, CT"]}},{"id":"midland-trail","name":"Midland Trail","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachia","states":"West Virginia","sub":"West Virginia","length":"","lengthMi":null,"lat":38.4127,"lng":-82.3605,"approxLoc":false,"qualities":[],"blurb":"The Midland Trail, also called the Roosevelt Midland Trail, was a national auto trail spanning the United States from Washington, D.C., west to Los Angeles, California and San Francisco, California (though the Lincoln Highway guide published in 1916 states the original eastern terminus was in New York City). First road signed in 1913, it was one of the first, if not the first, marked transcontinental auto trails in America.","link":"https://www.fhwa.dot.gov/byways","wiki":["Midland Trail"]},{"id":"mohawk-towpath-byway","name":"Mohawk Towpath Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Upstate New York","states":"New York","sub":"New York","length":"","lengthMi":null,"lat":42.9,"lng":-75.5,"approxLoc":true,"qualities":[],"blurb":"The Mohawk Towpath Scenic Byway is a National Scenic Byway in the Capital District region of New York in the United States. It extends from Schenectady to Waterford by way of a series of local, county, and state highways along the Mohawk River and the Erie Canal. The byway is intended to showcase the history of the waterway, from Native American times through the creation of the Erie Canal and the role the waterside communities played in the Industrial Revolution and the westward expansion of the United States. At ","link":"https://en.wikipedia.org/wiki/Mohawk_Towpath_Scenic_Byway","wiki":["Mohawk Towpath Byway","Mohawk Towpath Scenic Byway"],"endpoints":{"from":"Schenectady, NY","to":"Village of Waterford, NY","via":["Niskayuna, NY","Clifton Park, NY","Halfmoon, NY"]}},{"id":"mohawk-trail","name":"Mohawk Trail","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Massachusetts","sub":"Massachusetts","length":"","lengthMi":null,"lat":42.3,"lng":-71.8,"approxLoc":true,"qualities":[],"blurb":"The Mohawk Trail is a trail in Northern Massachusetts. The trail began as a Native American trade route which connected Atlantic tribes with tribes in Upstate New York and beyond. It followed the Millers River, Deerfield River and crossed the Hoosac Range, in the area that is now northwestern Massachusetts.","link":"https://www.fhwa.dot.gov/byways","wiki":["Mohawk Trail"]},{"id":"mount-hood-scenic-byway","name":"Mount Hood Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"97 mi","lengthMi":97,"lat":45.3735,"lng":-121.6959,"approxLoc":false,"qualities":[],"blurb":"The Mount Hood Highway No. 26 (see Oregon highways and routes) is the Oregon Department of Transportation's designation for a 96.74-mile-long (155.69 km) highway from Portland east around the south side of Mount Hood and north via Bennett Pass to Hood River. It is marked as U.S. Route 26 from Portland to near Mount Hood and Oregon Route 35 the rest of the way to Hood River. Much of the highway is part of the Mount Hood Scenic Byway, a National Scenic Byway which connects Troutdale with Hood River via the southern f","link":"https://www.fhwa.dot.gov/byways","wiki":["Mount Hood Scenic Byway","Mount Hood Highway"],"endpoints":{"from":"Portland, OR","to":"Hood River, OR","via":["Boring, OR","Sandy, OR","Government Camp, OR"]}},{"id":"mountains-to-sound-greenway","name":"Mountains to Sound Greenway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Washington","sub":"Washington","length":"","lengthMi":null,"lat":47.4,"lng":-120.5,"approxLoc":true,"qualities":[],"blurb":"The Mountains to Sound Greenway is a 1.5 million-acre landscape situated in Washington. On March 12, 2019, it was designated a National Heritage Area, to be managed by the Mountains to Sound Greenway Trust, as part of the John D. Dingell Jr. Conservation, Management, and Recreation Act. In 1998, it became the first National Scenic Byway to be designated in Washington. The corridor stretches along Interstate 90 between Seattle and Ellensburg, following several historic transportation routes and a network of bicyclin","link":"https://www.fhwa.dot.gov/byways","wiki":["Mountains to Sound Greenway"]},{"id":"native-american-scenic-byway","name":"Native American Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Great Plains","states":"North Dakota · South Dakota","sub":"North Dakota · South Dakota","length":"","lengthMi":null,"lat":47.5,"lng":-100.5,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Native American Scenic Byway"]},{"id":"nebo-loop-scenic-byway","name":"Nebo Loop Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"","lengthMi":null,"lat":40.0038,"lng":-111.7053,"approxLoc":false,"qualities":[],"blurb":"Mount Nebo is the southernmost and highest mountain in the Wasatch Range of Utah, in the United States, and the centerpiece of the Mount Nebo Wilderness, inside the Uinta National Forest. It is named after the biblical Mount Nebo in Jordan, overlooking the West Bank from the east of the Jordan River, which is said to be the place of Moses' death. Mount Nebo has two summits: the northern summit reaches 11,933 feet (3,637 m), and the southern summit reaches 11,882 feet (3,622 m). Early surveys placed the southern pea","link":"https://en.wikipedia.org/wiki/Mount_Nebo_(Utah)","wiki":["Nebo Loop Scenic Byway","Mount Nebo (Utah)"]},{"id":"ohio-river-scenic-byway","name":"Ohio River Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Midwest","states":"Illinois · Indiana · Ohio","sub":"Illinois · Indiana","length":"981 mi","lengthMi":981,"lat":40,"lng":-89.2,"approxLoc":true,"qualities":[],"blurb":"The Ohio River (Seneca: Ohi:yo') is a 981-mile-long (1,579 km) river in the United States. It is located at the boundary of the Midwestern and Southern United States, flowing in a southwesterly direction from Pittsburgh, Pennsylvania, to its mouth on the Mississippi River at Cairo, Illinois. It is the third largest river by discharge volume in the United States and the largest tributary by volume of the Mississippi River. It is also the sixth oldest river on the North American continent. The river flows through or ","link":"https://en.wikipedia.org/wiki/Ohio_River","wiki":["Ohio River Scenic Byway","Ohio River"]},{"id":"old-canada-road-scenic-byway","name":"Old Canada Road Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Maine Coast","states":"Maine","sub":"Maine","length":"157 mi","lengthMi":157,"lat":45.4,"lng":-69.2,"approxLoc":true,"qualities":[],"blurb":"U.S. Route 201 (US 201) is part of the nationwide system of United States Numbered Highways. It runs for 157.46 miles (253.41 km) entirely within the state of Maine and is a spur route of U.S. Route 1. Its southern terminus is in Brunswick at US 1 and Maine State Route 24 Business. Its northern terminus is at the Canada–US border near Jackman (a terminus it shares with Maine State Route 6), where it connects to Quebec Route 173. Between Solon and its northern terminus, US 201 is known as the Old Canada Road Nationa","link":"https://en.wikipedia.org/wiki/U.S._Route_201","wiki":["Old Canada Road Scenic Byway","U.S. Route 201"],"endpoints":{"from":"Brunswick, ME","to":"Sandy Bay, ME","via":["Gardiner, ME","Fairfield, ME","Bingham, ME"]}},{"id":"old-king-s-highway","name":"Old King's Highway","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Massachusetts","sub":"Massachusetts","length":"62 mi","lengthMi":62,"lat":42.3,"lng":-71.8,"approxLoc":true,"qualities":[],"blurb":"Massachusetts Route 6A is the state road for two sections formerly known as U.S. Route 6 (US 6) on Cape Cod. Most of Route 6A is also known as the Old King's Highway. Combining the 2 major sections (and a \"silent\" concurrency with US 6 through Eastham, Wellfleet, and South Truro), the highway is approximately 62 miles (100 km) long.","link":"https://en.wikipedia.org/wiki/Massachusetts_Route_6A","wiki":["Old King's Highway","Massachusetts Route 6A"],"endpoints":{"from":"Bourne, MA","to":"Provincetown, MA","via":["West Barnstable, MA","Brewster, MA","Eastham, MA"]}},{"id":"outer-banks-scenic-byway","name":"Outer Banks Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachians","states":"North Carolina","sub":"North Carolina","length":"148 mi","lengthMi":148,"lat":35.5669,"lng":-75.4688,"approxLoc":false,"qualities":[],"blurb":"North Carolina Highway 12 (NC 12) is a 148.0-mile-long (238.2 km) primary state highway in the U.S. state of North Carolina, linking the peninsulas and islands of the Outer Banks. Most sections of NC 12 are two lanes wide, and there are also two North Carolina Ferry System routes which maintain continuity of the route as it traverses the Outer Banks region. NC 12 is part of the Outer Banks Scenic Byway, a National Scenic Byway. The first NC 12 appeared on the 1924 North Carolina Official Map and at its greatest len","link":"https://www.fhwa.dot.gov/byways","wiki":["Outer Banks Scenic Byway","North Carolina Highway 12"],"endpoints":{"from":"Sea Level, NC","to":"Corolla, NC","via":["Ocracoke, NC","Oregon Inlet, NC","Kitty Hawk, NC"]}},{"id":"palisades-scenic-byway","name":"Palisades Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"New Jersey","sub":"New Jersey","length":"38 mi","lengthMi":38,"lat":40.7447,"lng":-74.0421,"approxLoc":false,"qualities":[],"blurb":"The Palisades Interstate Parkway (PIP) is a 38.25-mile (61.56 km) controlled-access parkway in the U.S. states of New Jersey and New York. The parkway is a major commuter route into New York City from Rockland and Orange counties in New York and Bergen County in New Jersey. The southern terminus of the route is at the George Washington Bridge in Fort Lee, New Jersey, where it connects to Interstate 95 (I-95), US 1-9, and US 46. Its northern terminus is at a traffic circle in Fort Montgomery, New York, where the PIP","link":"https://www.fhwa.dot.gov/byways","wiki":["Palisades Scenic Byway","Palisades Interstate Parkway"],"endpoints":{"from":"Fort Lee, NJ","to":"Bear Mountain State Park, NJ","via":["Sparkill, NJ","West Nyack, NJ","Pomona, NJ"]}},{"id":"paul-bunyan-scenic-byway","name":"Paul Bunyan Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"North Woods","states":"Minnesota","sub":"Minnesota","length":"","lengthMi":null,"lat":47.3827,"lng":-94.612,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Paul Bunyan Scenic Byway"]},{"id":"payette-river-scenic-byway","name":"Payette River Scenic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Northern Rockies","states":"Idaho","sub":"Idaho","length":"","lengthMi":null,"lat":44.4,"lng":-114.6,"approxLoc":true,"qualities":[],"blurb":"State Highway 55 (SH-55) is an Idaho highway from Marsing to New Meadows, connecting with US-95 at both ends. From Marsing it travels east to Nampa, Meridian, and Eagle, then north to Horseshoe Bend. SH-55 then climbs the Payette River to Banks, then its north fork to the Long Valley, through the towns of Cascade and McCall. After descending a narrow canyon to Meadows, SH-55 terminates in New Meadows at the junction with US-95.","link":"https://en.wikipedia.org/wiki/Idaho_State_Highway_55","wiki":["Payette River Scenic Byway","Idaho State Highway 55"],"endpoints":{"from":"Marsing, ID","to":"New Meadows, ID","via":["Meridian, ID","Horseshoe Bend, ID","No major junctions, ID"]}},{"id":"peter-norbeck-scenic-byway","name":"Peter Norbeck Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Black Hills","states":"South Dakota","sub":"South Dakota","length":"","lengthMi":null,"lat":43.766,"lng":-103.3843,"approxLoc":false,"qualities":[],"blurb":"The Peter Norbeck Scenic Byway is a National Scenic Byway in the Black Hills National Forest in the southwestern part of the U.S. state of South Dakota. It is a loop which is composed of portions of U.S. Route 16A (US 16A), South Dakota Highway 244 (SD 244), SD 87, and SD 89. Parts of the byway enter Black Hills National Forest, Custer State Park, and the Mount Rushmore National Memorial; the byway also travels within five miles (eight point zero kilometres) of the Crazy Horse Memorial. The byway is named after Pet","link":"https://www.fhwa.dot.gov/byways","wiki":["Peter Norbeck Scenic Byway"]},{"id":"pine-barrens-byway","name":"Pine Barrens Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Mid-Atlantic","states":"New Jersey","sub":"New Jersey","length":"","lengthMi":null,"lat":40.2,"lng":-74.6,"approxLoc":true,"qualities":[],"blurb":"The New Jersey Scenic Byways system consists of roads in the U.S. state of New Jersey that have been recognized for their historical or natural qualities.","link":"https://www.fhwa.dot.gov/byways","wiki":["Pine Barrens Byway","List of New Jersey Scenic Byways"]},{"id":"pioneer-historic-byway","name":"Pioneer Historic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Northern Rockies","states":"Idaho","sub":"Idaho","length":"","lengthMi":null,"lat":44.4,"lng":-114.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Pioneer Historic Byway"]},{"id":"pyramid-lake-scenic-byway","name":"Pyramid Lake Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Great Basin","states":"Nevada","sub":"Nevada","length":"5 mi","lengthMi":5,"lat":40.0265,"lng":-119.5691,"approxLoc":false,"qualities":[],"blurb":"Route 447, consisting of County Route 447 (CR 447) and State Route 447 (SR 447) is a highway in the U.S. state of Nevada. The highway is almost entirely within Washoe County but does for a brief time enter Pershing County. The highway connects the town of Gerlach to the remainder of the state via Wadsworth. Though passing through extremely remote and desolate areas of Nevada, the highway has recently gained fame as the primary route to access the Black Rock Desert, the site of the annual Burning Man festival. A 4.5","link":"https://www.fhwa.dot.gov/byways","wiki":["Pyramid Lake Scenic Byway","Nevada State Route 447"],"endpoints":{"from":"Wadsworth, NV","to":"Gerlach, NV","via":["Nixon, NV","No major junctions, NV"]}},{"id":"rangeley-lakes-scenic-byway","name":"Rangeley Lakes Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Maine Coast","states":"Maine","sub":"Maine","length":"","lengthMi":null,"lat":45.4,"lng":-69.2,"approxLoc":true,"qualities":[],"blurb":"The Rangeley Lakes Scenic Byway is a National Scenic Byway in the US state of Maine. This byway follows State Route 17 (SR 17) and SR 4 in the western part of the state which is home to the many lakes and streams for which the region is known. The Rangeley Lakes Scenic Byway begins on SR 4 outside the town of Rangeley and then continues on SR 17 after wrapping around Rangeley Lake. The route follows the ridgeline of the Appalachian Mountains before dropping into hills and valleys.","link":"https://en.wikipedia.org/wiki/Rangeley_Lakes_Scenic_Byway","wiki":["Rangeley Lakes Scenic Byway","Rangeley Lakes Scenic Byway"]},{"id":"red-river-gorge-scenic-byway","name":"Red River Gorge Scenic Byway","tier":"national-scenic-byway","region":"South","regionLabel":"Appalachia","states":"Kentucky","sub":"Kentucky","length":"","lengthMi":null,"lat":37.5,"lng":-85.3,"approxLoc":true,"qualities":[],"blurb":"The Red River Gorge is a canyon system on the Red River in east-central Kentucky, United States. Geologically it is part of the Pottsville Escarpment. The gorge lies within the Daniel Boone National Forest and was subsequently designated the Red River Gorge Geological Area, an area of around 29,000 acres (12,000 ha; 120 km2; 45 sq mi). It was designated a National Natural Landmark and National Archaeological District in 1976, and listed on the National Register of Historic Places. The 13,379-acre (5,414 ha; 54.14 k","link":"https://en.wikipedia.org/wiki/Red_River_Gorge","wiki":["Red River Gorge Scenic Byway","Red River Gorge"]},{"id":"revolutionary-heritage-byway","name":"Revolutionary Heritage Byway","tier":"national-scenic-byway","region":"East","regionLabel":"New England","states":"Rhode Island","sub":"Rhode Island","length":"","lengthMi":null,"lat":41.7,"lng":-71.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Revolutionary Heritage Byway"]},{"id":"river-road-scenic-byway","name":"River Road Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Great Lakes","states":"Michigan","sub":"Michigan","length":"2 mi","lengthMi":2,"lat":44.3,"lng":-85.6,"approxLoc":true,"qualities":[],"blurb":"The River Road National Scenic Byway (also called the River Road National Forest Scenic Byway) is a National Scenic Byway and National Forest Scenic Byway in the US state of Michigan. This 23+1⁄2-mile-long (37.8 km) byway follows M-65 and River Road; it extends eastward into the Huron National Forest and ends in the historic community of Oscoda near Lake Huron. The road parallels the historic Au Sable River (French: Rivière aux Sable, \"River of Sand\") which has historically been a major transportation route for flo","link":"https://en.wikipedia.org/wiki/River_Road_National_Scenic_Byway","wiki":["River Road Scenic Byway","River Road National Scenic Byway"],"endpoints":{"from":"Plainfield Township, MI","to":"Oscoda, MI","via":["Oscoda Township, MI"]}},{"id":"rogue-umpqua-scenic-byway","name":"Rogue-Umpqua Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Oregon","sub":"Oregon","length":"","lengthMi":null,"lat":43.0412,"lng":-122.4717,"approxLoc":false,"qualities":[],"blurb":"The Rogue-Umpqua Scenic Byway is a National Scenic Byway in the U.S. state of Oregon. It provides a tour of the environs of the North Umpqua River, the High Cascades, and the Upper Rogue River.","link":"https://www.fhwa.dot.gov/byways","wiki":["Rogue-Umpqua Scenic Byway"],"endpoints":{"from":"Roseburg, OR","to":"Gold Hill, OR","via":["Diamond Lake, OR","Union Creek, OR","Trail, OR"]}},{"id":"russell-brasstown-scenic-byway","name":"Russell-Brasstown Scenic Byway","tier":"national-scenic-byway","region":"South","regionLabel":"Southern Appalachians","states":"Georgia","sub":"Georgia","length":"","lengthMi":null,"lat":33,"lng":-83.5,"approxLoc":true,"qualities":[],"blurb":"The Russell–Brasstown Scenic Byway is a National Scenic Byway in the U.S. state of Georgia that includes parts of Georgia State Route 17 (SR 17), SR 75, SR 180, and SR 75 Alternate, as well as the entire length of SR 348. Surrounded by the beauty of the Chattahoochee-Oconee National Forest, the byway winds through the valleys and mountain gaps of the southern Appalachian Mountains. From the vistas atop Brasstown Bald to the cooling mists of waterfalls, scenic wonders fill this region.","link":"https://en.wikipedia.org/wiki/Russell%E2%80%93Brasstown_Scenic_Byway","wiki":["Russell-Brasstown Scenic Byway","Russell–Brasstown Scenic Byway"]},{"id":"sandhills-journey-scenic-byway","name":"Sandhills Journey Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Great Plains","states":"Nebraska","sub":"Nebraska","length":"","lengthMi":null,"lat":41.3997,"lng":-99.614,"approxLoc":false,"qualities":[],"blurb":"Nebraska Highway 2 (N-2) is a state highway in Nebraska consisting of two discontinuous segments. The western segment begins at the South Dakota border northwest of Crawford and ends southeast of Grand Island at an intersection with Interstate 80 (I-80). The eastern segment begins in Lincoln and ends at the Iowa border at Nebraska City. Previously, the two segments were connected via a route shared with U.S. Highway 34 (US 34) between Grand Island and Lincoln.","link":"https://www.fhwa.dot.gov/byways","wiki":["Sandhills Journey Scenic Byway","Nebraska Highway 2"],"endpoints":{"from":"Fall River, NE","to":"Missouri River, NE","via":["Thedford, NE","Grand Island, NE","Four Mile Precinct, NE"]}},{"id":"santa-fe-trail","name":"Santa Fe Trail","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"New Mexico","sub":"New Mexico","length":"","lengthMi":null,"lat":35.6127,"lng":-105.2054,"approxLoc":false,"qualities":[],"blurb":"The Santa Fe Trail was a 19th-century route through central North America that connected Franklin, Missouri, with Santa Fe, New Mexico. Pioneered in 1821 by William Becknell, who departed from the Boonslick region along the Missouri River, the trail served as a vital commercial highway until 1880, when the railroad arrived in Santa Fe. Santa Fe was near the end of El Camino Real de Tierra Adentro which carried trade from Mexico City. The trail was later incorporated into parts of the National Old Trails Road and U.","link":"https://en.wikipedia.org/wiki/Santa_Fe_Trail","wiki":["Santa Fe Trail","Santa Fe Trail"]},{"id":"savannah-river-scenic-byway","name":"Savannah River Scenic Byway","tier":"national-scenic-byway","region":"South","regionLabel":"Carolina Lowcountry","states":"South Carolina","sub":"South Carolina","length":"","lengthMi":null,"lat":33.1479,"lng":-81.7516,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Savannah River Scenic Byway"],"endpoints":{"from":"Edisto Beach, SC","to":"Osborn, SC","via":["Adams Run, SC"]}},{"id":"scenic-highway-30a","name":"Scenic Highway 30A","tier":"national-scenic-byway","region":"South","regionLabel":"Florida","states":"Florida","sub":"Florida","length":"","lengthMi":null,"lat":28.6,"lng":-81.5,"approxLoc":true,"qualities":[],"blurb":"State Road 30A (SR 30A) is a Florida Department of Transportation designation shared by four alternate routings of SR 30 in the Florida panhandle. Two segments have SR 30A signage; the other two do not as they are segments of U.S. Route 98 (US 98). Three of the four SR 30A segments are next to the shore of the Gulf of Mexico for most (if not all) of their length.","link":"https://en.wikipedia.org/wiki/Florida_State_Road_30A","wiki":["Scenic Highway 30A","Florida State Road 30A"]},{"id":"scenic-highway-of-legends","name":"Scenic Highway of Legends","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"Luis Alberto Dubuc Jr. (born January 28, 1985) is an American DJ, musician, singer-songwriter, record producer and former drummer from Dallas, Texas. He was a member of The Secret Handshake and Of Legends. He is currently the man behind Mystery Skulls.","link":"https://en.wikipedia.org/wiki/Luis_Dubuc","wiki":["Scenic Highway of Legends","Luis Dubuc"]},{"id":"schoodic-scenic-byway","name":"Schoodic Scenic Byway","tier":"national-scenic-byway","region":"East","regionLabel":"Maine Coast","states":"Maine","sub":"Maine","length":"","lengthMi":null,"lat":45.4,"lng":-69.2,"approxLoc":true,"qualities":[],"blurb":"Acadia National Park is a national park of the United States located along the mid-section of the Maine coast, southwest of Bar Harbor. The park includes about half of Mount Desert Island, part of Isle au Haut, the tip of the Schoodic Peninsula, and portions of sixteen smaller outlying islands. The park contains the tallest mountain on the Atlantic Coast of the United States (Cadillac Mountain), exposed granite domes, glacial erratics, U-shaped valleys, and cobble beaches. Its mountains, lakes, streams, wetlands, f","link":"https://en.wikipedia.org/wiki/Acadia_National_Park","wiki":["Schoodic Scenic Byway","Acadia National Park"]},{"id":"seaway-trail","name":"Seaway Trail","tier":"national-scenic-byway","region":"East","regionLabel":"Upstate New York","states":"New York · Pennsylvania","sub":"New York · Pennsylvania","length":"518 mi","lengthMi":518,"lat":44.1388,"lng":-75.3934,"approxLoc":false,"qualities":[],"blurb":"The Great Lakes Seaway Trail, formerly named and commonly known as the Seaway Trail, is a 518-mile (834 km) National Scenic Byway in the northeastern United States, mostly contained in New York but with a small segment in Pennsylvania. The trail consists of a series of designated roads and highways that travel along the Saint Lawrence Seaway—specifically, Lake Erie, the Niagara River, Lake Ontario, and the Saint Lawrence River. It begins at the Ohio state line in rural Erie County, Pennsylvania, and travels through","link":"https://en.wikipedia.org/wiki/Great_Lakes_Seaway_Trail","wiki":["Seaway Trail","Great Lakes Seaway Trail"]},{"id":"sheyenne-river-valley-scenic-byway","name":"Sheyenne River Valley Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Great Plains","states":"North Dakota","sub":"North Dakota","length":"","lengthMi":null,"lat":47.5,"lng":-100.5,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Sheyenne River Valley Scenic Byway"],"endpoints":{"from":"Beach Township, ND","to":"Red River of the North, ND","via":["Missouri River, ND","Jamestown, ND","West Fargo, ND"]}},{"id":"silver-thread-scenic-byway","name":"Silver Thread Scenic Byway","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"","lengthMi":null,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Silver Thread Scenic Byway"]},{"id":"sky-island-scenic-byway","name":"Sky Island Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"Arizona","sub":"Arizona","length":"","lengthMi":null,"lat":31.5628,"lng":-110.2934,"approxLoc":false,"qualities":[],"blurb":"The Catalina Highway, officially the General Hitchcock Highway, is the popular name for a Forest Highway and scenic route located in Pima County in southern Arizona. Also known as the Sky Island Scenic Byway, the Mount Lemmon Highway and Arizona Forest Highway 39, the Catalina Highway is the only paved roadway providing access to the resort village of Summerhaven as well as various recreational and scientific facilities located near the summit of Mount Lemmon. Ascending from the desert floor in Tucson to near the s","link":"https://www.fhwa.dot.gov/byways","wiki":["Sky Island Scenic Byway","Catalina Highway"]},{"id":"skyline-drive","name":"Skyline Drive","tier":"national-scenic-byway","region":"East","regionLabel":"Blue Ridge","states":"Virginia","sub":"Virginia","length":"105 mi","lengthMi":105,"lat":36.9133,"lng":-76.2282,"approxLoc":false,"qualities":[],"blurb":"Skyline Drive is a 105-mile (169 km) National Parkway that runs the entire length of the National Park Service's Shenandoah National Park in the Blue Ridge Mountains of Virginia, generally along the ridge of the mountains. The drive's northern terminus is at an intersection with U.S. Route 340 (US 340) near Front Royal, and the southern terminus is at an interchange with US 250 near Interstate 64 (I-64) in Rockfish Gap, where the road continues south as the Blue Ridge Parkway. The road has intermediate interchanges","link":"https://en.wikipedia.org/wiki/Skyline_Drive","wiki":["Skyline Drive","Skyline Drive"],"endpoints":{"from":"Front Royal, VA","to":"Waynesboro, VA"}},{"id":"talimena-scenic-drive","name":"Talimena Scenic Drive","tier":"national-scenic-byway","region":"South","regionLabel":"Ozarks","states":"Arkansas · Oklahoma","sub":"Arkansas · Oklahoma","length":"54 mi","lengthMi":54,"lat":34.9,"lng":-92.4,"approxLoc":true,"qualities":[],"blurb":"The Talimena Scenic Drive is a National Scenic Byway in southeastern Oklahoma and extreme western Arkansas spanning a 54.0-mile (86.9 km) stretch of Oklahoma State Highway 1 (SH-1) and Arkansas Highway 88 (AR 88) from Talihina, Oklahoma, to Mena, Arkansas.","link":"https://www.fhwa.dot.gov/byways","wiki":["Talimena Scenic Drive"]},{"id":"talladega-scenic-drive","name":"Talladega Scenic Drive","tier":"national-scenic-byway","region":"South","regionLabel":"Deep South","states":"Alabama","sub":"Alabama","length":"","lengthMi":null,"lat":33.5219,"lng":-85.751,"approxLoc":false,"qualities":[],"blurb":"State Route 281 in Alabama, also known as SR 281 and as Talladega Scenic Drive, extends from U.S. Route 78/State Route 9 (US 78/SR 9) west of Heflin to the intersection of two forest roads in the Talladega National Forest. Running the crest of the Talladega Mountains, Alabama's highest range, SR 281 was originally an unpaved forest route known as Skyway Motorway prior to the reconstruction into a paved scenic highway. SR 281 connects traffic to Cheaha State Park, a state park built on top of the highest point in th","link":"https://en.wikipedia.org/wiki/Alabama_State_Route_281","wiki":["Talladega Scenic Drive","Alabama State Route 281"],"endpoints":{"from":"Talladega National Forest, AL","to":"Cheaha State Park, AL","via":[]}},{"id":"tioga-pass","name":"Tioga Pass","tier":"national-scenic-byway","region":"West","regionLabel":"California","states":"California","sub":"California","length":"","lengthMi":null,"lat":37.2,"lng":-119.4,"approxLoc":true,"qualities":[],"blurb":"Tioga Pass is a mountain pass in the Sierra Nevada mountain range of California. State Route 120 runs through it, and serves as the eastern entry point for Yosemite National Park, at the Tioga Pass Entrance Station. It is the highest elevation highway pass in California and in the Sierra Nevada at an elevation of 9,945 ft (3,031 m). Mount Dana is to the east of the pass, and Gaylor Peak to the west.","link":"https://en.wikipedia.org/wiki/Tioga_Pass","wiki":["Tioga Pass","Tioga Pass"]},{"id":"top-of-the-rockies","name":"Top of the Rockies","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"115 mi","lengthMi":115,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"The Top of the Rockies National Scenic Byway is a National Scenic Byway and Colorado Scenic and Historic Byway located in the high Rocky Mountains of Eagle, Lake, Pitkin, Summit counties, Colorado, United States. The 115-mile (185 km) byway showcases the two highest peaks of the Rocky Mountains: Mount Elbert at elevation 14,440 feet (4,401.2 m) and Mount Massive at elevation 14,428 feet (4,398 m). The byway connects with the Collegiate Peaks Scenic Byway at the junction of Colorado State Highway 82 and U.S. Highway","link":"https://en.wikipedia.org/wiki/Top_of_the_Rockies_National_Scenic_Byway","wiki":["Top of the Rockies","Top of the Rockies National Scenic Byway"],"endpoints":{"from":"Aspen, CO","to":"Minturn, CO","via":["Leadville, CO"]}},{"id":"trail-of-the-ancients","name":"Trail of the Ancients","tier":"national-scenic-byway","region":"Rockies","regionLabel":"Colorado Rockies","states":"Colorado","sub":"Colorado","length":"366 mi","lengthMi":366,"lat":39,"lng":-105.6,"approxLoc":true,"qualities":[],"blurb":"The Trail of the Ancients is a collection of National Scenic Byways located in the U.S. Four Corners states of Utah, Colorado, New Mexico, and Arizona. These byways comprise: The 366-mile (589 km) Trail of the Ancients National Scenic Byway in San Juan County, Utah; The 116-mile (187 km) Trail of the Ancients Scenic and Historic Byway in Montezuma County, Colorado; The 662.4-mile (1,066 km) Trail of the Ancients Scenic Byway in McKinley and San Juan counties, New Mexico; The 100.3-mile (161 km) Dine' Tah \"Among the","link":"https://en.wikipedia.org/wiki/Trail_of_the_Ancients","wiki":["Trail of the Ancients","Trail of the Ancients"]},{"id":"turquoise-trail","name":"Turquoise Trail","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Desert Southwest","states":"New Mexico","sub":"New Mexico","length":"54 mi","lengthMi":54,"lat":35.5903,"lng":-106.0466,"approxLoc":false,"qualities":[],"blurb":"New Mexico State Road 14 (NM 14) is an approximately 54-mile-long (87 km) state road located in northern New Mexico. The highway connects Albuquerque to Santa Fe and comprises most of the Turquoise Trail, a National Scenic Byway which also includes NM 536 (Sandia Crest Scenic Byway).","link":"https://en.wikipedia.org/wiki/New_Mexico_State_Road_14","wiki":["Turquoise Trail","New Mexico State Road 14"],"endpoints":{"from":"Tijeras, NM","to":"Santa Fe, NM","via":["Madrid, NM"]}},{"id":"utah-scenic-byway-143","name":"Utah Scenic Byway 143","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"","lengthMi":null,"lat":38.0084,"lng":-111.3895,"approxLoc":false,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Utah Scenic Byway 143"],"endpoints":{"from":"Kanab, UT","to":"Garden City, UT","via":["Fairview, UT","North Salt Lake–Bountiful–Woods Cross tripoint, UT","Mantua, UT"]}},{"id":"washington-heritage-trail","name":"Washington Heritage Trail","tier":"national-scenic-byway","region":"East","regionLabel":"Appalachia","states":"West Virginia","sub":"West Virginia","length":"136 mi","lengthMi":136,"lat":39.4709,"lng":-78.3438,"approxLoc":false,"qualities":[],"blurb":"The Washington Heritage Trail is a 136.0-mile (218.9 km) National Scenic Byway through the easternmost counties of West Virginia's Eastern Panhandle. The trail forms a loop through the three counties and traces the footsteps of George Washington and the marks his family left in the Eastern Panhandle. In addition to homes and sites related to the Washingtons, the Washington Heritage Trail includes various museums, historic districts, parks, and other sites of historic significance in the area.","link":"https://www.fhwa.dot.gov/byways","wiki":["Washington Heritage Trail"]},{"id":"wetlands-and-wildlife-scenic-byway","name":"Wetlands and Wildlife Scenic Byway","tier":"national-scenic-byway","region":"Plains","regionLabel":"Great Plains","states":"Kansas","sub":"Kansas","length":"","lengthMi":null,"lat":38.5,"lng":-98.4,"approxLoc":true,"qualities":[],"blurb":"","link":"https://www.fhwa.dot.gov/byways","wiki":["Wetlands and Wildlife Scenic Byway"]},{"id":"white-mountain-trail","name":"White Mountain Trail","tier":"national-scenic-byway","region":"East","regionLabel":"White Mountains","states":"New Hampshire","sub":"New Hampshire","length":"100 mi","lengthMi":100,"lat":44.0542,"lng":-71.1643,"approxLoc":false,"qualities":[],"blurb":"The White Mountain Trail is a National Scenic Byway in the U.S. state of New Hampshire. It travels through the heart of the White Mountains crossing three major mountain passes. Despite the name it is a scenic byway accessible by car and not a hiking trail. The trail includes sections of U.S. Route 3 and US 302, between Lincoln and Conway, connecting at both ends with the Kancamagus Highway (part of New Hampshire Route 112). It also includes a branch which travels south from Bartlett to the Kancamagus over Bear Not","link":"https://www.fhwa.dot.gov/byways","wiki":["White Mountain Trail"]},{"id":"white-pass-scenic-byway","name":"White Pass Scenic Byway","tier":"national-scenic-byway","region":"West","regionLabel":"Cascades","states":"Washington","sub":"Washington","length":"431 mi","lengthMi":431,"lat":46.6387,"lng":-121.3893,"approxLoc":false,"qualities":[],"blurb":"U.S. Route 12 (US 12) is a major east–west U.S. Highway, running from Aberdeen, Washington, to Detroit, Michigan. It spans 430.5 miles (692.8 km) across the state of Washington, making it the second longest highway in the state. It is also the only numbered highway to span the entire state from west to east, starting near the Pacific Ocean, and crossing the Idaho state line near Clarkston. It crosses the Cascade Range over White Pass, south of Mount Rainier National Park. Portions of it are concurrent with Intersta","link":"https://www.fhwa.dot.gov/byways","wiki":["White Pass Scenic Byway","U.S. Route 12 in Washington"],"endpoints":{"from":"Aberdeen, WA","to":"Snake River, WA","via":["Silver Creek, WA","Sunnyside, WA","Waitsburg, WA"]}},{"id":"wilderness-road","name":"Wilderness Road","tier":"national-scenic-byway","region":"South","regionLabel":"Appalachia","states":"Kentucky","sub":"Kentucky","length":"","lengthMi":null,"lat":37.5,"lng":-85.3,"approxLoc":true,"qualities":[],"blurb":"The Wilderness Road was one of two principal routes used by colonial and early national era settlers to reach Kentucky from the East. Although this road goes through the Cumberland Gap into southern Kentucky and northern Tennessee, the other (more northern route) is sometimes called the \"Cumberland Road\" because it started in Fort Cumberland in Maryland. Despite Kentucky Senator Henry Clay's advocacy of this route early in the 19th century, the northern route was selected for the National Road, connecting near Wash","link":"https://en.wikipedia.org/wiki/Wilderness_Road","wiki":["Wilderness Road","Wilderness Road"]},{"id":"wisconsin-lake-superior-scenic-byway","name":"Wisconsin Lake Superior Scenic Byway","tier":"national-scenic-byway","region":"Midwest","regionLabel":"Great Lakes","states":"Wisconsin","sub":"Wisconsin","length":"","lengthMi":null,"lat":44.6,"lng":-89.9,"approxLoc":true,"qualities":[],"blurb":"The Wisconsin Scenic Byways are a system consisting of roads in the U.S. state of Wisconsin that travel through areas of scenic and historic interest. The intent of this system is to promote tourism and raise awareness of the communities along these routes. Wisconsin also has another system of scenic highways called Rustic Roads. There are five state-recognized scenic byways in Wisconsin, and three of them have also been designated National Scenic Byways.","link":"https://www.fhwa.dot.gov/byways","wiki":["Wisconsin Lake Superior Scenic Byway","List of Wisconsin Scenic Byways"]},{"id":"zion-park-scenic-byway","name":"Zion Park Scenic Byway","tier":"national-scenic-byway","region":"Southwest","regionLabel":"Utah Canyon Country","states":"Utah","sub":"Utah","length":"57 mi","lengthMi":57,"lat":37.2241,"lng":-112.9037,"approxLoc":false,"qualities":[],"blurb":"State Route 9 (SR-9) is a 57.075-mile-long (91.853 km) state highway in southern Utah, serving Zion National Park. It starts at the western terminus at exit 16 on Interstate 15 (I-15), passing through Zion National Park, and ending at the eastern junction with U.S. Route 89 (US-89). The entire length of the highway has been designated the Zion Park Scenic Byway. There is a fee to travel through Zion National Park, but the Zion-Mt. Carmel Highway is open to private vehicles year-round. A separate fee is required for","link":"https://en.wikipedia.org/wiki/Utah_State_Route_9","wiki":["Zion Park Scenic Byway","Utah State Route 9"],"endpoints":{"from":"Hurricane, UT","to":"Mt. Carmel Junction, UT","via":["La Verkin, UT","Rockville, UT","Zion National Park, UT"]}}];
